window.WARLOCK_INDEX_CORPUS=[{"title":"Documentation Index","type":"Navigation","path":"library/index.html","summary":"Use this index to move through standards, source registers, maps, assessments, actor profiles, source packets, timelines, trackers, and synthesis matrices.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Global","domain":"Corpus","tags":["documentation","index","navigation","global","corpus"]},{"title":"Assessment Index","type":"Directory","path":"library/assessments/index.html","summary":"Assessments are dated analytical products. They are written for strategic understanding and research continuity, not for operational direction.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Assessments","domain":"Assessments","tags":["assessment","index","assessments","readme","directory"]},{"title":"Coverage Map","type":"Document","path":"library/collections/coverage-map.html","summary":"This map defines the initial archive architecture for WARLOCK-INDEX. It is not a list of recommendations. It is a research coverage model for organizing future open-source defense assessments.","productId":"","preparedUtc":"2026-06-16T05:12:39Z","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Coverage Map","tags":["coverage","map","collections","coverage-map","document","coverage map","2026-06-16t05:12:39z"]},{"title":"Product Standard","type":"Standard","path":"library/standards/product-standard.html","summary":"This standard defines the minimum structure for WARLOCK-INDEX analytical products. It is designed to keep the repository useful to defense researchers and decision-support readers while preventing drift into unsupported claims, policy advocacy, or operational instruction.","productId":"WI-STD-001","preparedUtc":"2026-06-12T23:20:35Z","cutoffUtc":"","confidence":"","theater":"Global","domain":"Tradecraft","tags":["product","standard","standards","product-standard","global","tradecraft","wi-std-001","2026-06-12t23:20:35z"]},{"title":"Source Evaluation Standard","type":"Standard","path":"library/standards/source-evaluation.html","summary":"WARLOCK-INDEX uses four source classes:","productId":"WI-STD-002","preparedUtc":"2026-06-12T23:20:35Z","cutoffUtc":"","confidence":"","theater":"Global","domain":"Tradecraft","tags":["source","evaluation","standard","standards","source-evaluation","global","tradecraft","wi-std-002","2026-06-12t23:20:35z"]},{"title":"Official U.S. Source Register","type":"Source Register","path":"library/source-registers/official-us.html","summary":"U.S. official source-family routing for Quad diplomatic statements, factsheets, ministerial meetings, and future India/Quad strategic-partner source refresh.","productId":"","preparedUtc":"2026-06-16T05:12:39Z","cutoffUtc":"","confidence":"","theater":"Global","domain":"Sources","tags":["official","source","register","source-registers","official-us","source register","global","sources","2026-06-16t05:12:39z"]},{"title":"Allied And Multilateral Source Register","type":"Source Register","path":"library/source-registers/allied-multilateral.html","summary":"Official Quad source-family routing for partner terminology, meeting architecture, key publications, priority areas, ASEAN/Pacific/Indian Ocean coordination, and India/Quad strategic-partner source work.","productId":"","preparedUtc":"2026-06-16T05:12:39Z","cutoffUtc":"","confidence":"","theater":"Global","domain":"Sources","tags":["allied","and","multilateral","source","register","source-registers","allied-multilateral","source register","global","sources","2026-06-16t05:12:39z"]},{"title":"Research And Media Source Register","type":"Source Register","path":"library/source-registers/research-and-media.html","summary":"Conflict updates, especially Ukraine, Russia, Iran, and related military-political analysis.","productId":"","preparedUtc":"2026-06-13T03:20:02Z","cutoffUtc":"","confidence":"","theater":"Global","domain":"Sources","tags":["research","and","media","source","register","source-registers","research-and-media","source register","global","sources","2026-06-13t03:20:02z"]},{"title":"Maps","type":"Map Resource","path":"library/maps/index.html","summary":"Maps is the WARLOCK-INDEX hub for public map and geospatial references: official map portals, charting sources, geographic-name references, and theater map packets.","productId":"","preparedUtc":"2026-06-14T20:37:05Z","cutoffUtc":"2026-06-14T20:37:05Z","confidence":"","theater":"Global","domain":"Maps","tags":["maps","readme","map resource","global","2026-06-14t20:37:05z"]},{"title":"Actor Profiles","type":"Directory","path":"library/collections/actor-profiles/index.html","summary":"Actor Profiles compares strategic actors by objectives, capabilities, constraints, behavior patterns, leadership signals, and source confidence.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Actor Profiles","tags":["actor","profiles","collections","actor-profiles","readme","directory","actor profiles"]},{"title":"China Actor Profile","type":"Actor Profile","path":"library/collections/actor-profiles/china.html","summary":"China / PRC is classified for WARLOCK-INDEX purposes as:","productId":"WI-ACTOR-CHINA-2026-0001","preparedUtc":"2026-06-12T23:38:27Z","cutoffUtc":"2026-06-12T23:38:27Z","confidence":"","theater":"Collections","domain":"Actor Profiles","tags":["china","actor","profile","collections","actor-profiles","actor profile","actor profiles","wi-actor-china-2026-0001","2026-06-12t23:38:27z"]},{"title":"Foreign Terrorist Organizations And Nonstate Armed Networks Actor Profile Lane","type":"Directory","path":"library/collections/actor-profiles/foreign-terrorist-organizations-and-nonstate-armed-networks/index.html","summary":"Organize future profiles, source notes, timelines, and indicator watchlists for foreign terrorist organizations and major nonstate armed networks affecting U.S. homeland security, overseas personnel, partner stability, maritime disruption, regional conflicts, information operations, foreign fighter flows, and state-proxy relationships.","productId":"","preparedUtc":"2026-06-13T01:35:35Z","cutoffUtc":"2026-06-13T01:35:35Z","confidence":"","theater":"Collections","domain":"Foreign Terrorist Organizations And Nonstate Armed Networks","tags":["foreign","terrorist","organizations","and","nonstate","armed","networks","actor","profile","lane","collections","actor-profiles","foreign-terrorist-organizations-and-nonstate-armed-networks","readme","directory","foreign terrorist organizations and nonstate armed networks","2026-06-13t01:35:35z"]},{"title":"Foreign Terrorist Organizations And Nonstate Armed Networks Strategic Actor Classification","type":"Actor Profile","path":"library/collections/actor-profiles/foreign-terrorist-organizations-and-nonstate-armed-networks/2026-06-13T0141Z-foreign-terrorist-organizations-nonstate-armed-networks-strategic-actor-classification.html","summary":"Foreign terrorist organizations and major nonstate armed networks are best classified in WARLOCK-INDEX as distributed coercive violence ecosystems. They are not a single actor class with one ideology, sponsor, method, or geography. They include jihadist networks, Iran-aligned armed groups, nationalist and separatist organizations, state-proxy militias, maritime disruption actors, regional insurgent networks, designated criminal-terror hybrids, and online mobilization ecosystems that can inspire or enable individuals far from any formal battlefield.","productId":"WI-ACTOR-FTONSA-2026-0001","preparedUtc":"2026-06-13T01:41:46Z","cutoffUtc":"2026-06-13T01:41:46Z","confidence":"High for public U.S. strategic threat framing, terrorist-financing categories, and broad actor-family classification; moderate for current affiliate strength, leadership continuity, external operations capability, proxy command relationships, online mobilization effects, and WMD-related intent.","theater":"Collections","domain":"Actor Profiles","tags":["foreign","terrorist","organizations","and","nonstate","armed","networks","strategic","actor","classification","collections","actor-profiles","foreign-terrorist-organizations-and-nonstate-armed-networks","2026-06-13t0141z-foreign-terrorist-organizations-nonstate-armed-networks-strategic-actor-classification","actor profile","actor profiles","wi-actor-ftonsa-2026-0001","2026-06-13t01:41:46z","high","for","public","threat","framing","terrorist-financing","categories","broad","actor-family","moderate","current","affiliate","strength","leadership","continuity","external","operations","capability","proxy","command","relationships","online","mobilization","effects","wmd-related","intent"]},{"title":"Houthi Red Sea Maritime Disruption Profile","type":"Actor Profile","path":"library/collections/actor-profiles/foreign-terrorist-organizations-and-nonstate-armed-networks/2026-06-13T0517Z-houthi-red-sea-maritime-disruption-profile.html","summary":"The Houthis are strategically relevant to WARLOCK-INDEX because they connect local Yemeni conflict dynamics to Red Sea maritime pressure, Iran-linked regional networks, international shipping risk, marine insurance, Suez Canal exposure, humanitarian logistics, and allied naval burden-sharing. Public sources support treating the group as a durable nonstate armed actor with regional and global effects, not merely as a local insurgent organization or a single incident generator.","productId":"WI-ACTOR-HOUTHI-REDSEA-2026-0001","preparedUtc":"2026-06-13T05:17:00Z","cutoffUtc":"2026-06-13T05:17:00Z","confidence":"High for public source identity, U.S. designation framing, UN and EU legal-diplomatic framing, and broad maritime-disruption effects. Moderate for internal Houthi decision calculus, direct Iranian command relationships, future attack tempo, and commercial market persistence.","theater":"Collections","domain":"Actor Profiles","tags":["houthi","red","sea","maritime","disruption","profile","collections","actor-profiles","foreign-terrorist-organizations-and-nonstate-armed-networks","2026-06-13t0517z-houthi-red-sea-maritime-disruption-profile","actor profile","actor profiles","wi-actor-houthi-redsea-2026-0001","2026-06-13t05:17:00z","high","for","public","source","identity","designation","framing","un","and","eu","legal-diplomatic","broad","maritime-disruption","effects","moderate","internal","decision","calculus","direct","iranian","command","relationships","future","attack","tempo","commercial","market","persistence"]},{"title":"Indo-Pacific Allies And Partners","type":"Directory","path":"library/collections/actor-profiles/indo-pacific-allies-and-partners/index.html","summary":"Indo-Pacific Allies And Partners tracks public posture, capacity, constraints, and source confidence for regional allies and partners.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Indo-Pacific","domain":"Indo Pacific Allies And Partners","tags":["indo-pacific","allies","and","partners","collections","actor-profiles","indo-pacific-allies-and-partners","readme","directory","indo pacific allies and partners"]},{"title":"Iran Actor Profile","type":"Actor Profile","path":"library/collections/actor-profiles/iran.html","summary":"Iran is classified for WARLOCK-INDEX purposes as:","productId":"WI-ACTOR-IRAN-2026-0001","preparedUtc":"2026-06-12T23:33:32Z","cutoffUtc":"2026-06-12T23:33:32Z","confidence":"","theater":"Collections","domain":"Actor Profiles","tags":["iran","actor","profile","collections","actor-profiles","actor profile","actor profiles","wi-actor-iran-2026-0001","2026-06-12t23:33:32z"]},{"title":"Japan-Philippines-Australia Allied Posture Profile","type":"Actor Profile","path":"library/collections/actor-profiles/indo-pacific-allies-and-partners/2026-06-13T0222Z-japan-philippines-australia-allied-posture-profile.html","summary":"Japan, the Philippines, and Australia form a strategically important allied and partner cluster for U.S. Indo-Pacific defense research. Their value is not interchangeable. Japan anchors the northern First Island Chain, advanced industrial cooperation, missile-defense relevance, and proximity to Taiwan, the Korean Peninsula, and the East China Sea. The Philippines anchors the southern approaches to Taiwan, the South China Sea, archipelagic access, and maritime-domain awareness. Australia anchors southern depth, undersea cooperation, defense-industrial scaling, AUKUS, and Indian Ocean-Pacific connectivity. Together they create a networked posture problem for China, a resilience problem for U.S. defense planning, and an alliance-management problem that is political, industrial, legal, and military at the same time.","productId":"WI-PROFILE-ALLY-INDOPACIFIC-2026-0001","preparedUtc":"2026-06-13T02:22:20Z","cutoffUtc":"2026-06-13T02:22:20Z","confidence":"Moderate to high for public alliance architecture, official strategic framing, and durable posture functions. Moderate for current implementation details because public sources vary in update cadence and operationally sensitive posture details are intentionally limited.","theater":"Indo-Pacific","domain":"Actor Profiles","tags":["japan-philippines-australia","allied","posture","profile","collections","actor-profiles","indo-pacific-allies-and-partners","2026-06-13t0222z-japan-philippines-australia-allied-posture-profile","actor profile","indo-pacific","actor profiles","wi-profile-ally-indopacific-2026-0001","2026-06-13t02:22:20z","moderate","to","high","for","public","alliance","architecture","official","strategic","framing","and","durable","functions","current","implementation","details","because","sources","vary","in","update","cadence","operationally","sensitive","are","intentionally","limited"]},{"title":"NATO Allied Capacity And Burden-Sharing Profile","type":"Actor Profile","path":"library/collections/actor-profiles/nato-and-major-us-allies/2026-06-13T0233Z-nato-allied-capacity-burden-sharing-profile.html","summary":"NATO is the United States' most consequential allied capacity framework. Its strategic value is not only the number of member states or the existence of Article 5. The Alliance matters because it links U.S. nuclear assurance, European conventional mass, military mobility, defense-industrial production, Ukraine support, Arctic and High North geography, cyber and space resilience, and political legitimacy into a single Euro-Atlantic security architecture.","productId":"WI-PROFILE-NATO-ALLY-2026-0001","preparedUtc":"2026-06-13T02:33:47Z","cutoffUtc":"2026-06-13T02:33:47Z","confidence":"High for NATO public doctrine, summit commitments, declared burden-sharing framework, and official threat framing. Moderate for implementation because public sources do not fully reveal readiness, mobilization capacity, industrial bottlenecks, political durability, or classified planning assumptions.","theater":"NATO / Allies","domain":"Actor Profiles","tags":["nato","allied","capacity","and","burden-sharing","profile","collections","actor-profiles","nato-and-major-us-allies","2026-06-13t0233z-nato-allied-capacity-burden-sharing-profile","actor profile","nato / allies","actor profiles","wi-profile-nato-ally-2026-0001","2026-06-13t02:33:47z","high","for","public","doctrine","summit","commitments","declared","framework","official","threat","framing","moderate","implementation","because","sources","do","not","fully","reveal","readiness","mobilization","industrial","bottlenecks","political","durability","or","classified","planning","assumptions"]},{"title":"NATO And Major U.S. Allies","type":"Directory","path":"library/collections/actor-profiles/nato-and-major-us-allies/index.html","summary":"NATO And Major U.S. Allies tracks alliance architecture, burden-sharing, industrial capacity, resilience, geography, and implementation signals.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"NATO / Allies","domain":"NATO And Major US Allies","tags":["nato","and","major","allies","collections","actor-profiles","nato-and-major-us-allies","readme","directory","nato / allies","nato and major us allies"]},{"title":"North Korea Actor Profile","type":"Actor Profile","path":"library/collections/actor-profiles/north-korea.html","summary":"North Korea / DPRK is classified for WARLOCK-INDEX purposes as:","productId":"WI-ACTOR-NORTH-KOREA-2026-0001","preparedUtc":"2026-06-13T00:09:21Z","cutoffUtc":"2026-06-13T00:09:21Z","confidence":"","theater":"Collections","domain":"Actor Profiles","tags":["north","korea","actor","profile","collections","actor-profiles","north-korea","actor profile","actor profiles","wi-actor-north-korea-2026-0001","2026-06-13t00:09:21z"]},{"title":"Republic Of Korea Allied Posture Profile","type":"Actor Profile","path":"library/collections/actor-profiles/indo-pacific-allies-and-partners/2026-06-13T0317Z-republic-of-korea-allied-posture-profile.html","summary":"The Republic of Korea is a high-capacity U.S. treaty ally whose strategic relevance extends beyond the Korean Peninsula. Its primary defense problem remains the DPRK nuclear, missile, conventional, cyber, and sanctions-evasion threat. At the same time, the ROK is increasingly connected to wider Indo-Pacific security through U.S.-Japan-ROK trilateral consultation, missile-warning cooperation, maritime security, economic security, advanced technology, defense industry, Ukraine-related indirect effects, and the U.S. extended-deterrence architecture.","productId":"WI-PROFILE-ALLY-INDOPACIFIC-2026-0002","preparedUtc":"2026-06-13T03:17:12Z","cutoffUtc":"2026-06-13T03:16:36Z","confidence":"High for official public alliance framing, U.S.-ROK extended-deterrence consultation architecture, and Japan-ROK-U.S. trilateral public commitments. Moderate for readiness, domestic political durability, operational availability, and future crisis behavior because those details are not fully visible in open sources.","theater":"Indo-Pacific","domain":"Actor Profiles","tags":["republic","of","korea","allied","posture","profile","collections","actor-profiles","indo-pacific-allies-and-partners","2026-06-13t0317z-republic-of-korea-allied-posture-profile","actor profile","indo-pacific","actor profiles","wi-profile-ally-indopacific-2026-0002","2026-06-13t03:17:12z","2026-06-13t03:16:36z","high","for","official","public","alliance","framing","-rok","extended-deterrence","consultation","architecture","and","japan-rok-u","trilateral","commitments","moderate","readiness","domestic","political","durability","operational","availability","future","crisis","behavior","because","those","details","are","not","fully","visible","in","open","sources"]},{"title":"Russia Actor Profile","type":"Actor Profile","path":"library/collections/actor-profiles/russia.html","summary":"Russia / Russian Federation is classified for WARLOCK-INDEX purposes as:","productId":"WI-ACTOR-RUSSIA-2026-0001","preparedUtc":"2026-06-12T23:42:12Z","cutoffUtc":"2026-06-12T23:42:12Z","confidence":"","theater":"Collections","domain":"Actor Profiles","tags":["russia","actor","profile","collections","actor-profiles","actor profile","actor profiles","wi-actor-russia-2026-0001","2026-06-12t23:42:12z"]},{"title":"Transnational Criminal Organizations Actor Profile Lane","type":"Directory","path":"library/collections/actor-profiles/transnational-criminal-organizations/index.html","summary":"Organize future profiles, source notes, timelines, and indicator watchlists for transnational criminal organizations affecting U.S. homeland security, border security, illicit finance, narcotics flows, corruption, cybercrime, ports, migration pressure, and foreign-state exploitation.","productId":"","preparedUtc":"2026-06-13T01:35:35Z","cutoffUtc":"2026-06-13T01:35:35Z","confidence":"","theater":"Collections","domain":"Transnational Criminal Organizations","tags":["transnational","criminal","organizations","actor","profile","lane","collections","actor-profiles","transnational-criminal-organizations","readme","directory","transnational criminal organizations","2026-06-13t01:35:35z"]},{"title":"Transnational Criminal Organizations Strategic Actor Classification","type":"Actor Profile","path":"library/collections/actor-profiles/transnational-criminal-organizations/2026-06-13T0139Z-transnational-criminal-organizations-strategic-actor-classification.html","summary":"Transnational criminal organizations are best classified in WARLOCK-INDEX as homeland-coupled strategic pressure networks. They are not peer military competitors and are analytically distinct from state adversaries. Their strategic weight comes from persistence, adaptability, illicit revenue, corruption, violence, public-health harm, smuggling services, money laundering, cyber-enabled fraud, intimidation of partner institutions, and their ability to exploit seams between domestic security, regional governance, global finance, shipping, migration, and state competition.","productId":"WI-ACTOR-TCO-2026-0001","preparedUtc":"2026-06-13T01:39:11Z","cutoffUtc":"2026-06-13T01:39:11Z","confidence":"High for broad public-source U.S. threat framing, illicit finance categories, and homeland relevance; moderate for current network structure, leadership cohesion, state-criminal convergence, corruption depth, revenue allocation, and cross-border adaptation timelines.","theater":"Collections","domain":"Actor Profiles","tags":["transnational","criminal","organizations","strategic","actor","classification","collections","actor-profiles","transnational-criminal-organizations","2026-06-13t0139z-transnational-criminal-organizations-strategic-actor-classification","actor profile","actor profiles","wi-actor-tco-2026-0001","2026-06-13t01:39:11z","high","for","broad","public-source","threat","framing","illicit","finance","categories","and","homeland","relevance","moderate","current","network","structure","leadership","cohesion","state-criminal","convergence","corruption","depth","revenue","allocation","cross-border","adaptation","timelines"]},{"title":"Africa Security Environment Strategic Baseline","type":"Assessment","path":"library/assessments/africa/2026-06-13T0152Z-africa-security-environment-strategic-baseline.html","summary":"Africa is a strategic environment, not a single uniform theater. It contains 54 sovereign states, major demographic growth, critical maritime approaches, large mineral resources, key diplomatic voting weight, major humanitarian crises, expanding terrorist networks, foreign influence competition, and partners whose security choices affect U.S. interests across Europe, the Middle East, the Indo-Pacific, and the homeland.","productId":"WI-ASMT-AFRICA-2026-0001","preparedUtc":"2026-06-13T01:52:27Z","cutoffUtc":"2026-06-13T01:52:27Z","confidence":"High for broad official U.S. framing of Africa as a transnational-threat, partner-capacity, and outside-influence environment. Moderate for armed-group expansion rates, coup trajectory, outside-state security relationships, illicit-mineral flows, China and Russia leverage, information environment effects, and the pace at which local conflicts gain direct homeland relevance.","theater":"Africa","domain":"Africa","tags":["africa","security","environment","strategic","baseline","assessments","2026-06-13t0152z-africa-security-environment-strategic-baseline","assessment","wi-asmt-africa-2026-0001","2026-06-13t01:52:27z","high","for","broad","official","framing","of","as","transnational-threat","partner-capacity","and","outside-influence","moderate","armed-group","expansion","rates","coup","trajectory","outside-state","relationships","illicit-mineral","flows","china","russia","leverage","information","effects","the","pace","at","which","local","conflicts","gain","direct","homeland","relevance"]},{"title":"Arctic And High North Strategic Baseline","type":"Assessment","path":"library/assessments/arctic-high-north/2026-06-13T0148Z-arctic-high-north-strategic-baseline.html","summary":"The Arctic and High North are a first-tier strategic theater for WARLOCK-INDEX because the region links the U.S. homeland, Canada, Greenland, NATO's northern flank, Russia's Kola Peninsula, PRC-Russia cooperation, missile warning, undersea infrastructure, space architecture, energy, shipping, and defense logistics. It is not a remote niche file. It is a northern approach to North America, a transatlantic military geography, a Russian nuclear and naval stronghold, and an increasingly accessible commercial and political arena.","productId":"WI-ASMT-ARCTIC-2026-0001","preparedUtc":"2026-06-13T01:48:56Z","cutoffUtc":"2026-06-13T01:48:56Z","confidence":"High for broad official U.S. strategic framing, Arctic actor taxonomy, NATO enlargement effects, and the public assessment that Russia is the principal Arctic military challenge. Moderate for current Russian readiness after Ukraine losses, PRC intent beyond economic and research access, the pace of polar route commercialization, undersea infrastructure vulnerability, and the exact military consequences of climate-driven access.","theater":"Arctic High North","domain":"Arctic High North","tags":["arctic","and","high","north","strategic","baseline","assessments","arctic-high-north","2026-06-13t0148z-arctic-high-north-strategic-baseline","assessment","arctic high north","wi-asmt-arctic-2026-0001","2026-06-13t01:48:56z","for","broad","official","framing","actor","taxonomy","nato","enlargement","effects","the","public","that","russia","is","principal","military","challenge","moderate","current","russian","readiness","after","ukraine","losses","prc","intent","beyond","economic","research","access","pace","of","polar","route","commercialization","undersea","infrastructure","vulnerability","exact","consequences","climate-driven"]},{"title":"China Strategic Actor Classification","type":"Assessment","path":"library/assessments/indo-pacific/2026-06-12T2338Z-china-strategic-actor-classification.html","summary":"China should be classified in WARLOCK-INDEX as the United States' principal long-range peer competitor: a party-state great power with global economic and technological reach, a rapidly modernizing military, expanding nuclear and space capabilities, persistent cyber access ambitions, and a coercive approach to sovereignty disputes. The PRC is not only an Indo-Pacific military problem. It is a whole-of-system competitor whose power sits at the intersection of the Chinese Communist Party, the People's Liberation Army, industrial policy, commercial scale, technology acquisition, maritime pressure, information control, and strategic alignment with other U.S. adversaries. Taiwan remains the most acute military flashpoint, but the broader strategic issue is whether Beijing can reshape regional and global order in ways that reduce U.S. freedom of action, weaken allied confidence, and normalize coercion as a tool of state power.","productId":"WI-ASMT-INDOPAC-2026-0002","preparedUtc":"2026-06-12T23:38:27Z","cutoffUtc":"2026-06-12T23:38:27Z","confidence":"High for broad actor classification and enduring PLA modernization trends; moderate for timelines, crisis decision-making, leadership intent, economic resilience, and how Beijing would behave under wartime pressure.","theater":"Indo Pacific","domain":"Indo Pacific","tags":["china","strategic","actor","classification","assessments","indo-pacific","2026-06-12t2338z-china-strategic-actor-classification","assessment","indo pacific","wi-asmt-indopac-2026-0002","2026-06-12t23:38:27z","high","for","broad","and","enduring","pla","modernization","trends","moderate","timelines","crisis","decision-making","leadership","intent","economic","resilience","how","beijing","would","behave","under","wartime","pressure"]},{"title":"Global Cyber And Critical Infrastructure Strategic Baseline","type":"Assessment","path":"library/assessments/technology-cyber-space/2026-06-13T0129Z-global-cyber-critical-infrastructure-strategic-baseline.html","summary":"Cyber and critical infrastructure risk is now a global strategic defense issue, not a narrow technical security file. Public U.S. intelligence reporting identifies China, Russia, Iran, North Korea, ransomware groups, cybercriminals, and hacktivists as continuing threats to U.S. networks and critical infrastructure. These actors differ in scale, discipline, intent, and capability, but they share a common strategic effect: they can reach into the homeland, private infrastructure, defense production, commercial logistics, financial systems, communications, space services, and public confidence without crossing borders in a conventional military sense.","productId":"WI-ASMT-TCS-2026-0001","preparedUtc":"2026-06-13T01:29:18Z","cutoffUtc":"2026-06-13T01:29:18Z","confidence":"High for actor-level public U.S. threat framing and broad critical infrastructure exposure; moderate for incident attribution, private-sector visibility, adversary intent in a crisis, and sector-specific disruption severity.","theater":"Technology Cyber Space","domain":"Technology Cyber Space","tags":["global","cyber","and","critical","infrastructure","strategic","baseline","assessments","technology-cyber-space","2026-06-13t0129z-global-cyber-critical-infrastructure-strategic-baseline","assessment","technology cyber space","wi-asmt-tcs-2026-0001","2026-06-13t01:29:18z","high","for","actor-level","public","threat","framing","broad","exposure","moderate","incident","attribution","private-sector","visibility","adversary","intent","in","crisis","sector-specific","disruption","severity"]},{"title":"Global Space And Counterspace Strategic Baseline","type":"Assessment","path":"library/assessments/technology-cyber-space/2026-06-13T0132Z-global-space-counterspace-strategic-baseline.html","summary":"Space is now a strategic dependency layer for the United States, its allies, commercial society, and adversary military systems. Public U.S. intelligence reporting describes space as increasingly contested, with China and Russia developing counterspace capabilities and a wider range of state and nonstate actors able to use space services for military, commercial, intelligence, criminal, and terrorist purposes. The result is a domain in which warning, communications, navigation, missile tracking, weather, timing, logistics, finance, agriculture, disaster response, intelligence, and military operations are linked to orbital systems and their ground infrastructure.","productId":"WI-ASMT-TCS-2026-0002","preparedUtc":"2026-06-13T01:32:49Z","cutoffUtc":"2026-06-13T01:32:49Z","confidence":"High for broad public U.S. threat framing and PRC space/counterspace trends; moderate for classified system performance, on-orbit intent, wartime escalation thresholds, commercial-provider resilience, and Russian space-industrial recovery under sanctions.","theater":"Technology Cyber Space","domain":"Technology Cyber Space","tags":["global","space","and","counterspace","strategic","baseline","assessments","technology-cyber-space","2026-06-13t0132z-global-space-counterspace-strategic-baseline","assessment","technology cyber space","wi-asmt-tcs-2026-0002","2026-06-13t01:32:49z","high","for","broad","public","threat","framing","prc","trends","moderate","classified","system","performance","on-orbit","intent","wartime","escalation","thresholds","commercial-provider","resilience","russian","space-industrial","recovery","under","sanctions"]},{"title":"Global Strategic Operating Picture","type":"Assessment","path":"library/assessments/global/2026-06-13T0049Z-global-strategic-operating-picture.html","summary":"The global security environment confronting the United States is best understood as a simultaneity problem: multiple adversarial actors, unstable regions, nonstate networks, contested domains, and industrial constraints now interact in ways that can compound pressure faster than any single theater file can capture. China is the principal long-range peer competitor. Russia is the principal Euro-Atlantic military threat and an active war belligerent. Iran is a degraded but persistent regional revolutionary security state with missile, maritime, proxy, cyber, and WMD-related relevance. North Korea is a nuclear-armed regional adversary with homeland missile relevance, cyber-finance activity, and direct support to Russia's war. Transnational criminal organizations, foreign terrorist networks, cyber actors, and defense industrial bottlenecks widen the threat surface beyond conventional military balance.","productId":"WI-ASMT-GLOBAL-2026-0002","preparedUtc":"2026-06-13T00:49:30Z","cutoffUtc":"2026-06-13T00:49:30Z","confidence":"High for broad strategic structure and actor classification; moderate for cross-theater timing, crisis interaction, adversary coordination depth, defense industrial surge timelines, and the pace of technology adoption.","theater":"Global","domain":"Global","tags":["global","strategic","operating","picture","assessments","2026-06-13t0049z-global-strategic-operating-picture","assessment","wi-asmt-global-2026-0002","2026-06-13t00:49:30z","high","for","broad","structure","and","actor","classification","moderate","cross-theater","timing","crisis","interaction","adversary","coordination","depth","defense","industrial","surge","timelines","the","pace","of","technology","adoption"]},{"title":"Iran Strategic Actor Classification","type":"Assessment","path":"library/assessments/middle-east/2026-06-12T2333Z-iran-strategic-actor-classification.html","summary":"Iran should be classified in WARLOCK-INDEX as an adversarial regional power under severe strategic stress, with enduring asymmetric reach, WMD-related risk, cyber capability, proxy-network influence, maritime disruption capacity, and a regime-survival security structure centered on the Islamic Revolutionary Guard Corps. Iran is weakened relative to its pre-2025 posture, but it is not strategically spent. The most important classification point is that Iran's power is distributed across state institutions, security services, missiles and uncrewed systems, cyber units, ideological networks, partner militias, and regional geography. Damage to one element can reduce capability without eliminating the broader threat system.","productId":"WI-ASMT-MIDEAST-2026-0001","preparedUtc":"2026-06-12T23:33:32Z","cutoffUtc":"2026-06-12T23:33:32Z","confidence":"Moderate. Public official sources are strong for high-level classification, enduring doctrine, and current U.S. threat framing. Confidence is lower on internal Iranian decision-making, nuclear-site status, leadership cohesion, and the pace of post-conflict recovery.","theater":"Middle East","domain":"Middle East","tags":["iran","strategic","actor","classification","assessments","middle-east","2026-06-12t2333z-iran-strategic-actor-classification","assessment","middle east","wi-asmt-mideast-2026-0001","2026-06-12t23:33:32z","moderate","public","official","sources","are","strong","for","high-level","enduring","doctrine","and","current","threat","framing","confidence","is","lower","on","internal","iranian","decision-making","nuclear-site","status","leadership","cohesion","the","pace","of","post-conflict","recovery"]},{"title":"North Korea Strategic Actor Classification","type":"Assessment","path":"library/assessments/indo-pacific/2026-06-13T0009Z-north-korea-strategic-actor-classification.html","summary":"North Korea is classified in WARLOCK-INDEX as a nuclear-armed regional adversary with direct U.S. homeland relevance and acute Korean Peninsula flashpoint risk. The DPRK is not a great-power peer of the United States, but it is one of the most dangerous strategic actors in the Indo-Pacific because it combines a closed hereditary security regime, forward military posture, large-scale conventional forces, ballistic missile development, nuclear weapons, chemical weapons concerns, persistent cyber-enabled revenue generation, and deepening military support to Russia. Its power is brittle but consequential. Pyongyang uses threat perception, sanctions pressure, internal control, weapons demonstrations, and external patronage to preserve regime survival and extract strategic attention disproportionate to its economic weight.","productId":"WI-ASMT-INDOPAC-2026-0003","preparedUtc":"2026-06-13T00:09:21Z","cutoffUtc":"2026-06-13T00:09:21Z","confidence":"High for broad actor classification, nuclear and missile relevance, cyber-finance threat, and Korean Peninsula flashpoint status; moderate for internal regime decision-making, stockpile size, command and control resilience, Russia-DPRK transfer details, and wartime behavior under extreme pressure.","theater":"Indo Pacific","domain":"Indo Pacific","tags":["north","korea","strategic","actor","classification","assessments","indo-pacific","2026-06-13t0009z-north-korea-strategic-actor-classification","assessment","indo pacific","wi-asmt-indopac-2026-0003","2026-06-13t00:09:21z","high","for","broad","nuclear","and","missile","relevance","cyber-finance","threat","korean","peninsula","flashpoint","status","moderate","internal","regime","decision-making","stockpile","size","command","control","resilience","russia-dprk","transfer","details","wartime","behavior","under","extreme","pressure"]},{"title":"PRC Military Modernization And Indo-Pacific Balance","type":"Assessment","path":"library/assessments/indo-pacific/2026-06-12T2320Z-prc-military-modernization-strategic-baseline.html","summary":"The PRC's military modernization is the most consequential long-range challenge for U.S. defense planning because it joins political ambition, industrial scale, military-technical modernization, coercive pressure on Taiwan, and expanding global reach. Public U.S. reporting presents the PLA as focused on achieving regional military advantage along the First Island Chain while building the strategic, nuclear, cyber, space, maritime, air, missile, and information capabilities needed to challenge U.S. intervention in a regional crisis. The central U.S. research problem is not whether the PLA is modernizing; it is how fast modernization translates into usable coercive power, how Beijing measures risk, and how PRC capabilities interact with allied cohesion, industrial depth, and crisis communication.","productId":"WI-ASMT-INDOPAC-2026-0001","preparedUtc":"2026-06-12T23:20:35Z","cutoffUtc":"2026-06-12T23:20:35Z","confidence":"Moderate to high. The source base is strong for public U.S. assessments of PRC objectives and capabilities, but PRC decision-making, wartime performance, and crisis behavior remain uncertain.","theater":"Indo Pacific","domain":"Indo Pacific","tags":["prc","military","modernization","and","indo-pacific","balance","assessments","2026-06-12t2320z-prc-military-modernization-strategic-baseline","assessment","indo pacific","wi-asmt-indopac-2026-0001","2026-06-12t23:20:35z","moderate","to","high","the","source","base","is","strong","for","public","of","objectives","capabilities","but","decision-making","wartime","performance","crisis","behavior","remain","uncertain"]},{"title":"Red Sea Maritime Disruption Strategic Baseline","type":"Assessment","path":"library/assessments/middle-east/2026-06-13T0516Z-red-sea-maritime-disruption-strategic-baseline.html","summary":"The Red Sea maritime disruption file is a strategic chokepoint problem, a Middle East escalation problem, an Iran-linked nonstate-network problem, and a global commerce problem at the same time. Public sources support the judgment that the Houthis can impose international cost and uncertainty without controlling the full maritime corridor. Their leverage comes from geography, durable political-military organization inside Yemen, external support, regional-conflict narrative, and the sensitivity of commercial shipping, insurance, naval presence, humanitarian logistics, and Suez-linked revenue to perceived risk.","productId":"WI-ASMT-MIDEAST-2026-0002","preparedUtc":"2026-06-13T05:16:07Z","cutoffUtc":"2026-06-13T05:16:07Z","confidence":"High for source identity, official designation framing, UN and EU legal-diplomatic framing, Suez Canal Authority traffic statistics, and UNCTAD chokepoint indicators. Moderate for Houthi decision calculus, Iran-Houthi command relationships, insurance pricing effects, commercial behavioral persistence, and future disruption tempo.","theater":"Middle East","domain":"Middle East","tags":["red","sea","maritime","disruption","strategic","baseline","assessments","middle-east","2026-06-13t0516z-red-sea-maritime-disruption-strategic-baseline","assessment","middle east","wi-asmt-mideast-2026-0002","2026-06-13t05:16:07z","high","for","source","identity","official","designation","framing","un","and","eu","legal-diplomatic","suez","canal","authority","traffic","statistics","unctad","chokepoint","indicators","moderate","houthi","decision","calculus","iran-houthi","command","relationships","insurance","pricing","effects","commercial","behavioral","persistence","future","tempo"]},{"title":"Russia Strategic Actor Classification","type":"Assessment","path":"library/assessments/europe-russia/2026-06-12T2342Z-russia-strategic-actor-classification.html","summary":"Russia should be classified in WARLOCK-INDEX as a revisionist nuclear peer adversary and the principal military threat to Euro-Atlantic security. It is not the same type of competitor as China: Russia has a smaller economic base and weaker long-term demographic position, but it retains the world's largest nuclear arsenal, a wartime-mobilized defense industry, extensive experience in high-intensity war, undersea and space capabilities, cyber and intelligence services, Arctic military geography, and a record of hybrid pressure against NATO states and partners. The Russia problem is therefore not only a Ukraine problem. It is an enduring U.S. and allied defense problem linking nuclear deterrence, European conventional defense, long-range strike, chemical weapons norms, sanctions resilience, defense industrial capacity, and adversary coordination with China, Iran, North Korea, and Belarus.","productId":"WI-ASMT-EURRUS-2026-0001","preparedUtc":"2026-06-12T23:42:12Z","cutoffUtc":"2026-06-12T23:42:12Z","confidence":"High for Russia's broad actor classification, nuclear-peer status, NATO threat role, and ongoing war centrality; moderate for force regeneration timelines, sanctions resilience, domestic elite stability, weapons production rates, and Moscow's crisis decision thresholds.","theater":"Europe Russia","domain":"Europe Russia","tags":["russia","strategic","actor","classification","assessments","europe-russia","2026-06-12t2342z-russia-strategic-actor-classification","assessment","europe russia","wi-asmt-eurrus-2026-0001","2026-06-12t23:42:12z","high","for","broad","nuclear-peer","status","nato","threat","role","and","ongoing","war","centrality","moderate","force","regeneration","timelines","sanctions","resilience","domestic","elite","stability","weapons","production","rates","moscow","crisis","decision","thresholds"]},{"title":"Strategic Environment Baseline, 2026","type":"Assessment","path":"library/assessments/global/2026-06-12T2320Z-strategic-environment-baseline.html","summary":"The 2026 strategic environment is defined by simultaneous pressure on the U.S. homeland, the Western Hemisphere, the Indo-Pacific balance of power, European security, and the global defense industrial base. Public U.S. and NATO sources portray a world in which armed conflict is more common, military technology is diffusing, strategic competitors are coordinating more often, and contested domains such as cyber, space, long-range strike, AI, and quantum technologies are becoming central to national defense. The central analytical requirement for this repository is disciplined prioritization: not every conflict is equally important to U.S. interests, but several theaters now interact through supply chains, alliance commitments, sanctions, arms production, information warfare, and adversary cooperation.","productId":"WI-ASMT-GLOBAL-2026-0001","preparedUtc":"2026-06-12T23:20:35Z","cutoffUtc":"2026-06-12T23:20:35Z","confidence":"Moderate. The major judgments are supported by strong official sources, but several conflicts and technology domains are changing rapidly.","theater":"Global","domain":"Global","tags":["strategic","environment","baseline","2026","assessments","global","2026-06-12t2320z-strategic-environment-baseline","assessment","wi-asmt-global-2026-0001","2026-06-12t23:20:35z","moderate","the","major","judgments","are","supported","by","strong","official","sources","but","several","conflicts","and","technology","domains","changing","rapidly"]},{"title":"Taiwan Strait And First Island Chain Strategic Baseline","type":"Assessment","path":"library/assessments/indo-pacific/2026-06-13T0123Z-taiwan-strait-first-island-chain-strategic-baseline.html","summary":"The Taiwan Strait and First Island Chain are the central Indo-Pacific flashpoint for U.S. defense research because they connect PRC sovereignty claims, PLA modernization, U.S. alliance credibility, maritime geography, semiconductor production, Japanese and Philippine security, Guam, the South China Sea, and the global economy in a single pressure system. Public U.S. sources identify the First Island Chain as the current strategic center of gravity for PRC military focus and describe Taiwan as a primary scenario in which Beijing could attempt coercive or forceful unification.","productId":"WI-ASMT-INDOPAC-2026-0004","preparedUtc":"2026-06-13T01:23:47Z","cutoffUtc":"2026-06-13T01:23:47Z","confidence":"High for public U.S. strategic framing and broad theater geography; moderate for PRC decision timing, crisis thresholds, PLA wartime performance, allied political behavior under pressure, and the precise economic effects of a Taiwan Strait crisis.","theater":"Indo Pacific","domain":"Indo Pacific","tags":["taiwan","strait","and","first","island","chain","strategic","baseline","assessments","indo-pacific","2026-06-13t0123z-taiwan-strait-first-island-chain-strategic-baseline","assessment","indo pacific","wi-asmt-indopac-2026-0004","2026-06-13t01:23:47z","high","for","public","framing","broad","theater","geography","moderate","prc","decision","timing","crisis","thresholds","pla","wartime","performance","allied","political","behavior","under","pressure","the","precise","economic","effects","of"]},{"title":"U.S. Defense Industrial Base Strategic Baseline","type":"Assessment","path":"library/assessments/defense-industrial-base/2026-06-13T0117Z-us-defense-industrial-base-strategic-baseline.html","summary":"The U.S. defense industrial base is a strategic center of gravity for the WARLOCK-INDEX corpus. Public U.S. strategy now treats industrial capacity as one of the main pillars of national defense, not as an administrative support function. The 2026 National Defense Strategy identifies rebuilding and supercharging the defense industrial base as a central line of effort and links the DIB to homeland defense, Indo-Pacific deterrence, allied burden-sharing, and the ability to sustain the force under stress. The 2025 National Security Strategy similarly connects American industrial strength, critical supply chains, technology, financial leverage, and strategic geography to long-term security.","productId":"WI-ASMT-DIB-2026-0001","preparedUtc":"2026-06-13T01:17:09Z","cutoffUtc":"2026-06-13T01:17:09Z","confidence":"High for broad public strategic prioritization and core industrial-base categories; moderate for current production rates, sub-tier supplier fragility, classified stockpile levels, surge timelines, critical mineral dependencies, wartime transportation capacity, and allied industrial integration.","theater":"Defense Industrial Base","domain":"Defense Industrial Base","tags":["defense","industrial","base","strategic","baseline","assessments","defense-industrial-base","2026-06-13t0117z-us-defense-industrial-base-strategic-baseline","assessment","defense industrial base","wi-asmt-dib-2026-0001","2026-06-13t01:17:09z","high","for","broad","public","prioritization","and","core","industrial-base","categories","moderate","current","production","rates","sub-tier","supplier","fragility","classified","stockpile","levels","surge","timelines","critical","mineral","dependencies","wartime","transportation","capacity","allied","integration"]},{"title":"U.S. Homeland And Western Hemisphere Strategic Baseline","type":"Assessment","path":"library/assessments/homeland-hemisphere/2026-06-13T0110Z-us-homeland-western-hemisphere-strategic-baseline.html","summary":"The U.S. homeland and Western Hemisphere are now a primary strategic lane for WARLOCK-INDEX. Public U.S. sources no longer treat the homeland as a protected rear area separated from overseas military competition. ODNI's 2026 assessment places transnational organized crime, illicit drug trafficking, migration, terrorism, major-power competition, WMD threats, Arctic activity, and advanced delivery systems inside the homeland threat frame. The 2026 National Defense Strategy makes defense of the U.S. homeland the first public defense line of effort and ties that priority to the Western Hemisphere. The 2025 National Security Strategy frames the hemisphere as a strategic geography where migration, drug flows, key terrain, supply chains, foreign influence, and access to strategic locations affect U.S. security and prosperity.","productId":"WI-ASMT-HOMELAND-2026-0001","preparedUtc":"2026-06-13T01:10:07Z","cutoffUtc":"2026-06-13T01:10:07Z","confidence":"High for broad public-source threat taxonomy and official U.S. strategic prioritization; moderate for current criminal network adaptation, foreign influence depth, migration surge timing, cyber pre-positioning, Arctic military activity, and state-criminal overlap.","theater":"Homeland Hemisphere","domain":"Homeland Hemisphere","tags":["homeland","and","western","hemisphere","strategic","baseline","assessments","homeland-hemisphere","2026-06-13t0110z-us-homeland-western-hemisphere-strategic-baseline","assessment","homeland hemisphere","wi-asmt-homeland-2026-0001","2026-06-13t01:10:07z","high","for","broad","public-source","threat","taxonomy","official","prioritization","moderate","current","criminal","network","adaptation","foreign","influence","depth","migration","surge","timing","cyber","pre-positioning","arctic","military","activity","state-criminal","overlap"]},{"title":"U.S. Official Threat Source Operating Picture","type":"Assessment","path":"library/assessments/homeland-hemisphere/2026-06-13T0558Z-us-official-threat-source-operating-picture.html","summary":"The next stage of WARLOCK-INDEX should treat official U.S. threat coverage as a structured source system. The corpus already has strong defense and IC baselines for major foreign adversaries. The gap is a wider, indexed source architecture for CIA, FBI, DHS, CISA, NSA, State, Treasury, DEA, ATF, CBP, Coast Guard, DOJ, and NGA public products so readers can understand which agency source family supports which threat category.","productId":"WI-ASMT-HOMELAND-2026-0002","preparedUtc":"2026-06-13T05:58:00Z","cutoffUtc":"2026-06-13T05:58:00Z","confidence":"High for the source architecture and agency-source roles. Moderate for current document recency across dynamic public agency pages because some product URLs change or block automated verification.","theater":"Homeland Hemisphere","domain":"Homeland Hemisphere","tags":["official","threat","source","operating","picture","assessments","homeland-hemisphere","2026-06-13t0558z-us-official-threat-source-operating-picture","assessment","homeland hemisphere","wi-asmt-homeland-2026-0002","2026-06-13t05:58:00z","high","for","the","architecture","and","agency-source","roles","moderate","current","document","recency","across","dynamic","public","agency","pages","because","some","product","urls","change","or","block","automated","verification"]},{"title":"Global Actor-Domain Assimilation Matrix","type":"Matrix","path":"library/collections/global-assimilation/2026-06-13T0049Z-global-actor-domain-assimilation-matrix.html","summary":"Provide a reusable integration model for connecting actor profiles, theater assessments, source notes, event timelines, and domain files inside WARLOCK-INDEX.","productId":"WI-MATRIX-GLOBAL-2026-0001","preparedUtc":"2026-06-16T05:12:39Z","cutoffUtc":"2026-06-16T05:12:39Z","confidence":"","theater":"Collections","domain":"Global Assimilation","tags":["global","actor-domain","assimilation","matrix","collections","global-assimilation","2026-06-13t0049z-global-actor-domain-assimilation-matrix","global assimilation","wi-matrix-global-2026-0001","2026-06-16t05:12:39z"]},{"title":"Global Assimilation","type":"Directory","path":"library/collections/global-assimilation/index.html","summary":"Global Assimilation connects actors, theaters, domains, and source streams through cross-cutting matrices and synthesis tools.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Global Assimilation","tags":["global","assimilation","collections","global-assimilation","readme","directory","global assimilation"]},{"title":"Legacy Factbook Replacement Note","type":"Document","path":"library/collections/source-notes/2026-06-13T0938Z-legacy-factbook-replacement-note.html","summary":"CIA announced on February 4, 2026, that The World Factbook had sunset. WARLOCK-INDEX should treat the Factbook as a legacy reference after that date. It can support historical context where a product clearly marks the archival cutoff, but it should not carry current country facts.","productId":"","preparedUtc":"2026-06-13T09:38:00Z","cutoffUtc":"2026-06-13T09:38:00Z","confidence":"","theater":"Collections","domain":"Source Notes","tags":["legacy","factbook","replacement","note","collections","source-notes","2026-06-13t0938z-legacy-factbook-replacement-note","document","source notes","2026-06-13t09:38:00z"]},{"title":"Maritime Chokepoint Strategic Assimilation Matrix","type":"Matrix","path":"library/collections/global-assimilation/2026-06-13T0519Z-maritime-chokepoint-strategic-assimilation-matrix.html","summary":"Maritime chokepoints should be treated as strategic integration nodes rather than as isolated geography. Each chokepoint links actors, legal regimes, commercial flows, energy or commodity exposure, insurance confidence, allied response, infrastructure resilience, and escalation risk. The Red Sea/Suez lane now has the strongest WARLOCK-INDEX source packet. The remaining lanes should be expanded through separate dated source packets before the repository uses them for high-confidence comparative judgments.","productId":"WI-MATRIX-CHOKEPOINT-2026-0001","preparedUtc":"2026-06-13T05:19:00Z","cutoffUtc":"2026-06-13T05:19:00Z","confidence":"High for source organization and Red Sea/Suez source base. Moderate for comparative judgments across other chokepoints because this matrix intentionally summarizes lanes that require future source packets.","theater":"Collections","domain":"Global Assimilation","tags":["maritime","chokepoint","strategic","assimilation","matrix","collections","global-assimilation","2026-06-13t0519z-maritime-chokepoint-strategic-assimilation-matrix","global assimilation","wi-matrix-chokepoint-2026-0001","2026-06-13t05:19:00z","high","for","source","organization","and","red","sea","suez","base","moderate","comparative","judgments","across","other","chokepoints","because","this","intentionally","summarizes","lanes","that","require","future","packets"]},{"title":"ODNI Global Biolab Disclosure Source-Treatment Note","type":"Document","path":"library/collections/source-notes/2026-06-14T0347Z-odni-global-biolab-disclosure-source-treatment-note.html","summary":"ODNI released a June 12, 2026 public statement and linked declassified slides asserting longstanding U.S. Government funding for more than 120 foreign biolabs in more than 30 countries, including Ukraine. The ODNI statement also asserted that some laboratories may present oversight, compromise, hazardous research, and national-security concerns.","productId":"","preparedUtc":"2026-06-14T03:47:22Z","cutoffUtc":"2026-06-14T03:47:22Z","confidence":"High that ODNI publicly released the press release and linked PDF. Moderate to low for independent assessment of individual facility, funding, biological-material, research-characterization, and oversight claims until cross-read with DoD Cooperative Threat Reduction, State Department, congressional, Ukrainian, treaty-organization, technical biosecurity, and independent oversight sources.","theater":"Collections","domain":"Source Notes","tags":["odni","global","biolab","disclosure","source-treatment","note","collections","source-notes","2026-06-14t0347z-odni-global-biolab-disclosure-source-treatment-note","document","source notes","2026-06-14t03:47:22z","high","that","publicly","released","the","press","release","and","linked","pdf","moderate","to","low","for","independent","assessment","of","individual","facility","funding","biological-material","research-characterization","oversight","claims","until","cross-read","with","dod","cooperative","threat","reduction","state","department","congressional","ukrainian","treaty-organization","technical","biosecurity","sources"]},{"title":"Official Allied Source Assimilation Matrix","type":"Matrix","path":"library/collections/global-assimilation/2026-06-14T0118Z-official-allied-source-assimilation-matrix.html","summary":"Allied official-source coverage requires both multilateral and national layers. NATO sources establish consensus Alliance language, but national sources are needed for country-level defense policy, budgets, procurement, industrial capacity, cyber, space, resilience, and political implementation. The UK, Australia, Canada/NORAD, Japan, ROK, France, Germany, Norway, Finland, Sweden, Denmark, and Iceland lanes are now full national or continental-defense allied baselines, while the EU source packet provides the adjacent multilateral security-defense layer and the India/Quad packet creates the first explicitly partner-labeled Indo-Pacific strategic-partner lane. The AUKUS industrial and NORAD modernization packets are the first follow-on implementation source packets in the allied lane. Future country, partner, and implementation packets should follow the same model: source ledger, extraction matrix, domain treatment, information gaps, source register entries, tracker wiring, and matrix wiring.","productId":"WI-MATRIX-ALLY-SOURCES-2026-0001","preparedUtc":"2026-06-16T05:12:39Z","cutoffUtc":"2026-06-16T05:12:39Z","confidence":"High for assimilation logic and existing UK, Australia, AUKUS, Canada/NORAD, NORAD modernization, Japan, ROK, France, Germany, Norway, Finland, Sweden, Denmark, Iceland, EU, India/Quad partner, and NATO source routing. Moderate for broader allied-country coverage pending dated country packets and source-register expansion.","theater":"Collections","domain":"Global Assimilation","tags":["official","allied","source","assimilation","matrix","collections","global-assimilation","2026-06-14t0118z-official-allied-source-assimilation-matrix","global assimilation","wi-matrix-ally-sources-2026-0001","2026-06-16t05:12:39z","high","for","logic","and","existing","uk","australia","aukus","canada","norad","modernization","japan","rok","france","germany","norway","finland","sweden","denmark","iceland","eu","india","quad","partner","nato","routing","moderate","broader","allied-country","coverage","pending","dated","country","packets","source-register","expansion"]},{"title":"Official U.S. Threat Source Assimilation Matrix","type":"Matrix","path":"library/collections/global-assimilation/2026-06-13T0601Z-official-us-threat-source-assimilation-matrix.html","summary":"Official U.S. threat coverage belongs in a matrix because no single agency source family is sufficient. ODNI provides the IC-wide frame; CIA provides foreign reference material; FBI and DHS provide domestic and homeland law-enforcement framing; CISA/NSA/FBI provide cyber advisory streams; State and Treasury provide designations, sanctions, and terrorism finance; DEA, ATF, CBP, Coast Guard, and DOJ provide transnational crime, border, maritime, firearms, narcotics, and legal-case source streams; NGA and CIA maps provide geospatial reference at strategic level only.","productId":"WI-MATRIX-US-THREAT-SOURCES-2026-0001","preparedUtc":"2026-06-14T06:05:33Z","cutoffUtc":"2026-06-14T06:05:33Z","confidence":"High for organizing logic; moderate for current source completeness pending dated source packets for each agency family.","theater":"Collections","domain":"Global Assimilation","tags":["official","threat","source","assimilation","matrix","collections","global-assimilation","2026-06-13t0601z-official-us-threat-source-assimilation-matrix","global assimilation","wi-matrix-us-threat-sources-2026-0001","2026-06-14t06:05:33z","high","for","organizing","logic","moderate","current","completeness","pending","dated","packets","each","agency","family"]},{"title":"Source Notes","type":"Directory","path":"library/collections/source-notes/index.html","summary":"Source Notes preserves short provenance records for sources that need context before they are reused. Each note records date, URL, source class, and why the source matters.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Source Notes","tags":["source","notes","collections","source-notes","readme","directory","source notes"]},{"title":"Theater Map Index","type":"Document","path":"library/collections/source-notes/2026-06-13T1733Z-theater-map-index.html","summary":"Theater maps in WARLOCK-INDEX should answer a narrow question: which public source family can orient a reader to a theater without enabling operational misuse? The answer is different by lane. NGA public-release maps are the first stop for global and selected theater orientation. Combatant command area-of-responsibility pages can show U.S. command-area framing. USGS, NOAA, and the U.S. Board on Geographic Names cover U.S. topographic, maritime, and naming layers. NATO public map and member-country pages support alliance geography. State, foreign government, UN, and allied maps can add diplomatic or issuer-perspective context after dated refresh.","productId":"WI-MAPINDEX-THEATER-2026-0001","preparedUtc":"2026-06-13T17:33:00Z","cutoffUtc":"2026-06-13T17:33:00Z","confidence":"","theater":"Collections","domain":"Source Notes","tags":["theater","map","index","collections","source-notes","2026-06-13t1733z-theater-map-index","document","source notes","wi-mapindex-theater-2026-0001","2026-06-13t17:33:00z"]},{"title":"Ukraine Biolab Claim-Reconciliation Source Note","type":"Document","path":"library/collections/source-notes/2026-06-14T0412Z-ukraine-biolab-claim-reconciliation-source-note.html","summary":"The Ukraine biolab lane contains at least five separable source layers: ODNI's 2026 disclosure, earlier DoD/U.S. Embassy public threat-reduction framing, State Department and BWC treaty/diplomatic framing, Ukrainian government public statements, and Russian/PRC/information-environment claims. WARLOCK-INDEX should not collapse those layers into a single resolved finding.","productId":"","preparedUtc":"2026-06-14T04:12:00Z","cutoffUtc":"2026-06-14T04:12:00Z","confidence":"High for the existence and issuer identity of the ODNI release and DoD BTRP Ukraine fact sheet. Moderate for source-family mapping where State, U.S. Embassy, UN, and UNODA pages returned access barriers in this environment. Low for any attempt to adjudicate underlying technical, facility-level, legal, or intent claims without follow-on document-level corroboration.","theater":"Collections","domain":"Source Notes","tags":["ukraine","biolab","claim-reconciliation","source","note","collections","source-notes","2026-06-14t0412z-ukraine-biolab-claim-reconciliation-source-note","document","source notes","2026-06-14t04:12:00z","high","for","the","existence","and","issuer","identity","of","odni","release","dod","btrp","fact","sheet","moderate","source-family","mapping","where","state","embassy","un","unoda","pages","returned","access","barriers","in","this","environment","low","any","attempt","to","adjudicate","underlying","technical","facility-level","legal","or","intent","claims","without","follow-on","document-level","corroboration"]},{"title":"Arctic Militarization Strategic Event Timeline","type":"Timeline","path":"library/collections/event-timelines/2026-06-13T0212Z-arctic-militarization-strategic-event-timeline.html","summary":"The Arctic has shifted from a relatively insulated governance environment into a theater where homeland defense, NATO geography, Russian military posture, PRC access-seeking, climate change, undersea infrastructure, space support, and strategic-warning requirements intersect. Public U.S. sources identify the Arctic as a homeland-defense problem and an alliance problem at the same time: Russia retains substantial military infrastructure and strategic forces in the region, China seeks greater access and influence, and Finland and Sweden's NATO accession changed the High North military map.","productId":"WI-TIMELINE-ARCTIC-2026-0001","preparedUtc":"2026-06-13T02:12:17Z","cutoffUtc":"2026-06-13T02:12:17Z","confidence":"Moderate to high for major public milestones, official threat framing, NATO enlargement, and broad actor posture. Moderate for current force-specific interpretation because public sources intentionally limit detailed operational information.","theater":"Collections","domain":"Event Timelines","tags":["arctic","militarization","strategic","event","timeline","collections","event-timelines","2026-06-13t0212z-arctic-militarization-strategic-event-timeline","event timelines","wi-timeline-arctic-2026-0001","2026-06-13t02:12:17z","moderate","to","high","for","major","public","milestones","official","threat","framing","nato","enlargement","and","broad","actor","posture","current","force-specific","interpretation","because","sources","intentionally","limit","detailed","operational","information"]},{"title":"Event Timelines","type":"Directory","path":"library/collections/event-timelines/index.html","summary":"Event Timelines records dated sequences, source references, uncertainty notes, and links to the assessments that use each timeline.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Event Timelines","tags":["event","timelines","collections","event-timelines","readme","directory","event timelines"]},{"title":"Red Sea And Houthi Maritime Disruption Strategic Event Timeline","type":"Timeline","path":"library/collections/event-timelines/2026-06-13T0208Z-red-sea-houthi-maritime-disruption-strategic-event-timeline.html","summary":"The Red Sea disruption file is a maritime chokepoint problem, an Iran-linked network problem, a global-commerce problem, and a Middle East escalation problem at the same time. Public U.S. sources describe the Huthis as resilient, located to pressure Red Sea traffic, and able to threaten U.S. and partner interests. The January 2025 Ansar Allah order and 2026 ODNI assessment frame the group as more than a local Yemeni actor: it is a strategic disruptor whose geography allows coercive pressure against international shipping and against the political choices of states outside Yemen.","productId":"WI-TIMELINE-REDSEA-2026-0001","preparedUtc":"2026-06-13T02:08:52Z","cutoffUtc":"2026-06-13T02:08:52Z","confidence":"Moderate to high for major public events, designation status, and broad disruption patterns. Moderate for Houthi decision calculus, Iran-Houthi command relationships, and future crisis durability because public sources identify support relationships and effects more clearly than internal deliberations.","theater":"Collections","domain":"Event Timelines","tags":["red","sea","and","houthi","maritime","disruption","strategic","event","timeline","collections","event-timelines","2026-06-13t0208z-red-sea-houthi-maritime-disruption-strategic-event-timeline","event timelines","wi-timeline-redsea-2026-0001","2026-06-13t02:08:52z","moderate","to","high","for","major","public","events","designation","status","broad","patterns","decision","calculus","iran-houthi","command","relationships","future","crisis","durability","because","sources","identify","support","effects","more","clearly","than","internal","deliberations"]},{"title":"Strategic Weapons Modernization Strategic Event Timeline","type":"Timeline","path":"library/collections/event-timelines/2026-06-13T0215Z-strategic-weapons-modernization-strategic-event-timeline.html","summary":"Strategic weapons modernization has become a simultaneous, multi-actor pressure lane rather than a bilateral U.S.-Russia nuclear issue. Public U.S. sources describe a deteriorating environment in which Russia retains the largest and most diverse nuclear stockpile, China is rapidly expanding and diversifying its nuclear posture, North Korea is expanding nuclear and missile programs, Iran remains WMD- and missile-relevant, and counterspace systems are increasingly tied to nuclear warning, deterrence confidence, and missile defense. The strategic center of gravity is not a single weapon class. It is the interaction among nuclear forces, precision strike, missile defense, space-based warning, cyber-space disruption, and arms-control erosion.","productId":"WI-TIMELINE-STRATWEAPONS-2026-0001","preparedUtc":"2026-06-13T02:15:18Z","cutoffUtc":"2026-06-13T02:15:18Z","confidence":"Moderate to high for public strategic patterns, official threat framing, arms-control erosion, and major modernization milestones. Moderate for force-specific readiness, internal leadership calculus, and classified system performance because public sources deliberately limit operational detail.","theater":"Collections","domain":"Event Timelines","tags":["strategic","weapons","modernization","event","timeline","collections","event-timelines","2026-06-13t0215z-strategic-weapons-modernization-strategic-event-timeline","event timelines","wi-timeline-stratweapons-2026-0001","2026-06-13t02:15:18z","moderate","to","high","for","public","patterns","official","threat","framing","arms-control","erosion","and","major","milestones","force-specific","readiness","internal","leadership","calculus","classified","system","performance","because","sources","deliberately","limit","operational","detail"]},{"title":"Taiwan Strait Coercion Strategic Event Timeline","type":"Timeline","path":"library/collections/event-timelines/2026-06-13T0203Z-taiwan-strait-coercion-strategic-event-timeline.html","summary":"The Taiwan Strait coercion problem has moved from episodic political tension to a persistent strategic pressure campaign. Public U.S. sources present Taiwan as central to PRC national-rejuvenation narratives, PLA modernization goals, First Island Chain military planning, U.S. alliance credibility, semiconductor supply-chain risk, and the possibility of a wider Indo-Pacific crisis. The most important analytic pattern is simultaneity: military activity, legal-political pressure, economic measures, information activity, cyber risk, and allied signaling reinforce one another even when no single event by itself marks a decision for war.","productId":"WI-TIMELINE-TAIWAN-2026-0001","preparedUtc":"2026-06-13T02:03:36Z","cutoffUtc":"2026-06-13T02:03:36Z","confidence":"Moderate to high for broad strategic patterns and major public events. Moderate for interpretation of Beijing's internal risk calculus because public sources reveal behavior and official language more clearly than internal decision processes.","theater":"Collections","domain":"Event Timelines","tags":["taiwan","strait","coercion","strategic","event","timeline","collections","event-timelines","2026-06-13t0203z-taiwan-strait-coercion-strategic-event-timeline","event timelines","wi-timeline-taiwan-2026-0001","2026-06-13t02:03:36z","moderate","to","high","for","broad","patterns","and","major","public","events","interpretation","of","beijing","internal","risk","calculus","because","sources","reveal","behavior","official","language","more","clearly","than","decision","processes"]},{"title":"Ukraine War Strategic Event Timeline","type":"Timeline","path":"library/collections/event-timelines/2026-06-13T0157Z-ukraine-war-strategic-event-timeline.html","summary":"Russia's war against Ukraine is the central Euro-Atlantic conflict timeline for WARLOCK-INDEX. The timeline is not only a sequence of battlefield events. It is a record of how Russia's full-scale invasion changed NATO, European defense spending, U.S. and allied industrial demand, sanctions architecture, adversary cooperation, nuclear signaling, drone and missile warfare, critical-infrastructure risk, and global perceptions of the use of force.","productId":"WI-TIMELINE-UKRAINE-2026-0001","preparedUtc":"2026-06-13T01:57:52Z","cutoffUtc":"2026-06-13T01:57:52Z","confidence":"High for official diplomatic, alliance, and public IC events; moderate for battlefield turning points, sanctions adaptation, external-support details, sabotage attribution, and long-term industrial effects.","theater":"Collections","domain":"Event Timelines","tags":["ukraine","war","strategic","event","timeline","collections","event-timelines","2026-06-13t0157z-ukraine-war-strategic-event-timeline","event timelines","wi-timeline-ukraine-2026-0001","2026-06-13t01:57:52z","high","for","official","diplomatic","alliance","and","public","ic","events","moderate","battlefield","turning","points","sanctions","adaptation","external-support","details","sabotage","attribution","long-term","industrial","effects"]},{"title":"Arctic Infrastructure And Domain Awareness Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-13T0318Z-arctic-infrastructure-domain-awareness-source-packet.html","summary":"Arctic infrastructure is a strategic defense issue because the region connects homeland warning, NORAD, missile defense, space support, undersea and maritime access, communications, ports, airfields, icebreaking, civil resilience, indigenous and northern community needs, and NATO's High North geometry. The 2024 DoD Arctic Strategy identifies rapid geophysical and geopolitical change, PRC-Russia cooperation, Russian military infrastructure, NATO enlargement, climate-driven infrastructure degradation, domain awareness, communications, and a monitor-and-respond approach as core public-source themes. Canada adds a parallel northern-defense and community-infrastructure lens, while the ICE Pact makes icebreaking an industrial and allied-capacity lane.","productId":"WI-SOURCEPACKET-ARCTIC-INFRA-2026-0001","preparedUtc":"2026-06-13T03:18:04Z","cutoffUtc":"2026-06-13T03:16:36Z","confidence":"High for official public source identity and broad strategic themes around Arctic domain awareness, communications, climate effects, infrastructure stress, allied geography, icebreaking, and Canada-U.S.-Finland industrial collaboration. Moderate for implementation timelines, facility status, communications performance, and future access because public sources do not reveal sensitive infrastructure details or classified posture.","theater":"Arctic / High North","domain":"Source Packets","tags":["arctic","infrastructure","and","domain","awareness","source","packet","collections","source-packets","arctic-infrastructure","2026-06-13t0318z-arctic-infrastructure-domain-awareness-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-arctic-infra-2026-0001","2026-06-13t03:18:04z","2026-06-13t03:16:36z","high","for","official","public","identity","broad","strategic","themes","around","communications","climate","effects","stress","allied","geography","icebreaking","canada-u","-finland","industrial","collaboration","moderate","implementation","timelines","facility","status","performance","future","access","because","sources","do","not","reveal","sensitive","details","or","classified","posture"]},{"title":"Arctic Infrastructure Source Packets","type":"Directory","path":"library/collections/source-packets/arctic-infrastructure/index.html","summary":"Arctic Infrastructure Source Packets organize public evidence on northern infrastructure, domain awareness, communications, icebreaking, and resilience.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Arctic / High North","domain":"Arctic Infrastructure","tags":["arctic","infrastructure","source","packets","collections","source-packets","arctic-infrastructure","readme","directory","arctic / high north","arctic infrastructure"]},{"title":"Arms-Control Erosion Source Packet","type":"Source Packet","path":"library/collections/source-packets/strategic-weapons/2026-06-13T0320Z-arms-control-erosion-source-packet.html","summary":"Arms-control erosion is now a central strategic-weapons research lane. The New START treaty entered into force in 2011, was extended to February 5, 2026, and expired after Russia suspended implementation in 2023 and no successor agreement entered into force. Its expiration removes the last legally binding bilateral U.S.-Russia strategic nuclear arms limit and reduces treaty-based verification, transparency, and predictability. At the same time, official U.S., NATO, and WARLOCK-INDEX source lanes point to broader strategic-weapons pressure from PRC nuclear expansion, Russian nuclear signaling, DPRK nuclear and missile development, Iran-related WMD concerns, missile defense, space, cyber, hypersonics, and conventional-nuclear ambiguity.","productId":"WI-SOURCEPACKET-ARMSCONTROL-2026-0001","preparedUtc":"2026-06-13T03:20:02Z","cutoffUtc":"2026-06-13T03:16:36Z","confidence":"High for source identity, New START treaty history, key limits, Russian suspension, and treaty expiration as described by current research and official archives. Moderate for future arms-control trajectory, post-expiration restraint, verification substitutes, and multilateral prospects because these depend on state decisions and incomplete public evidence.","theater":"Global","domain":"Source Packets","tags":["arms-control","erosion","source","packet","collections","source-packets","strategic-weapons","2026-06-13t0320z-arms-control-erosion-source-packet","source packet","global","source packets","wi-sourcepacket-armscontrol-2026-0001","2026-06-13t03:20:02z","2026-06-13t03:16:36z","high","for","identity","new","start","treaty","history","key","limits","russian","suspension","and","expiration","as","described","by","current","research","official","archives","moderate","future","trajectory","post-expiration","restraint","verification","substitutes","multilateral","prospects","because","these","depend","on","state","decisions","incomplete","public","evidence"]},{"title":"AUKUS Industrial Implementation Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-allied-posture/2026-06-16T0153Z-aukus-industrial-implementation-source-packet.html","summary":"AUKUS industrial implementation should be treated as a multi-lane source problem rather than a single submarine-acquisition milestone. The official Australian source stack now separates program pathway, industrial strategy, build partner structure, sustainment partner structure, supplier qualification, workforce development, infrastructure projects, SRF-West preparation, and security/stewardship requirements. That separation is useful because each lane can move at a different speed and require different corroborating evidence.","productId":"WI-SOURCEPACKET-AUKUS-INDUSTRIAL-2026-0001","preparedUtc":"2026-06-16T01:53:21Z","cutoffUtc":"2026-06-16T01:53:21Z","confidence":"High for official source identity and declared public program architecture. Moderate for implementation status because official public pages identify milestones, partners, infrastructure projects, workforce programs, and source lanes, but do not independently prove cost, schedule, supplier depth, yard throughput, nuclear stewardship performance, classified readiness, or submarine availability.","theater":"Collections","domain":"Source Packets","tags":["aukus","industrial","implementation","source","packet","collections","source-packets","indo-pacific-allied-posture","2026-06-16t0153z-aukus-industrial-implementation-source-packet","source packet","source packets","wi-sourcepacket-aukus-industrial-2026-0001","2026-06-16t01:53:21z","high","for","official","identity","and","declared","public","program","architecture","moderate","status","because","pages","identify","milestones","partners","infrastructure","projects","workforce","programs","lanes","but","do","not","independently","prove","cost","schedule","supplier","depth","yard","throughput","nuclear","stewardship","performance","classified","readiness","or","submarine","availability"]},{"title":"Australia Official Defence And AUKUS Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-allied-posture/2026-06-14T0129Z-australia-official-defence-aukus-source-baseline-packet.html","summary":"Australia's official-source lane should be treated as both an Indo-Pacific allied posture file and an industrial-transformation file. The 2026 National Defence Strategy and Integrated Investment Program page is the current official public source anchor: it says the 2026 NDS builds on the 2023 Defence Strategic Review and 2024 NDS, reinforces the strategy of denial, and pairs defense capability with greater self-reliance, sovereign industrial resilience, international industrial partnerships, civil preparedness, and regional partner coordination. The 2024 NDS/IIP page remains useful because it introduced the National Defence framing and strategy of denial. The 2023 DSR is the reform baseline.","productId":"WI-SOURCEPACKET-AUS-ALLY-2026-0001","preparedUtc":"2026-06-14T01:29:53Z","cutoffUtc":"2026-06-14T01:29:53Z","confidence":"High for official Australian source identity, source family routing, and declared defense-strategy/AUKUS/cyber/industrial framing. Moderate for implementation judgments because official public pages and strategy documents do not by themselves prove schedule performance, readiness, workforce depth, shipyard throughput, industrial conversion, cyber maturity, budget execution, or classified operational constraints.","theater":"Collections","domain":"Source Packets","tags":["australia","official","defence","and","aukus","source","baseline","packet","collections","source-packets","indo-pacific-allied-posture","2026-06-14t0129z-australia-official-defence-aukus-source-baseline-packet","source packet","source packets","wi-sourcepacket-aus-ally-2026-0001","2026-06-14t01:29:53z","high","for","australian","identity","family","routing","declared","defense-strategy","cyber","industrial","framing","moderate","implementation","judgments","because","public","pages","strategy","documents","do","not","by","themselves","prove","schedule","performance","readiness","workforce","depth","shipyard","throughput","conversion","maturity","budget","execution","or","classified","operational","constraints"]},{"title":"Canada/NORAD Arctic And Continental Defense Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-14T0138Z-canada-norad-arctic-continental-defense-source-packet.html","summary":"Canada/NORAD official-source coverage should be treated as both an allied country lane and a continental-defense lane. Canada's *Our North, Strong and Free* page is the current public defense-policy anchor for Arctic sovereignty, defense of Canada, defense of North America, and NORAD modernization source work. The archived *Strong, Secure, Engaged* page remains useful as a legacy baseline, but current claims should route first through the newer policy, budget, annual-report, parliamentary, and program sources.","productId":"WI-SOURCEPACKET-CAN-NORAD-2026-0001","preparedUtc":"2026-06-14T01:38:22Z","cutoffUtc":"2026-06-14T01:38:22Z","confidence":"High for official public source identity, source family routing, and declared Canadian/NORAD strategic framing. Moderate for implementation, schedule, cost, readiness, sensor coverage, infrastructure status, and cyber maturity because public strategy and budget pages do not prove delivered capability and omit classified posture.","theater":"Arctic / High North","domain":"Source Packets","tags":["canada","norad","arctic","and","continental","defense","source","packet","collections","source-packets","arctic-infrastructure","2026-06-14t0138z-canada-norad-arctic-continental-defense-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-can-norad-2026-0001","2026-06-14t01:38:22z","high","for","official","public","identity","family","routing","declared","canadian","strategic","framing","moderate","implementation","schedule","cost","readiness","sensor","coverage","infrastructure","status","cyber","maturity","because","strategy","budget","pages","do","not","prove","delivered","capability","omit","classified","posture"]},{"title":"China Nuclear And Missile Modernization Source Packet","type":"Source Packet","path":"library/collections/source-packets/strategic-weapons/2026-06-13T0250Z-china-nuclear-missile-modernization-source-packet.html","summary":"The open-source official record supports treating PRC nuclear and missile modernization as a central strategic-weapons lane, not a narrow regional military issue. ODNI frames Beijing's nuclear modernization as tied to strategic competition with the United States and places China among actors developing advanced delivery systems with homeland relevance. The DoD PRC report provides the most detailed public baseline for China's nuclear expansion, early-warning counterstrike development, missile and hypersonic portfolio, PLA Rocket Force role, and post-Strategic Support Force reorganization. The 2022 NDS/NPR/MDR supplies the two-major-power deterrence frame, and NATO's Washington declaration shows that PRC nuclear expansion, space activity, and Russia-defense-industrial support now carry Euro-Atlantic security significance.","productId":"WI-SOURCEPACKET-CHINA-STRATWEAPONS-2026-0001","preparedUtc":"2026-06-13T02:50:08Z","cutoffUtc":"2026-06-13T02:50:08Z","confidence":"High for official public source identity, publication date, stated source scope, and broad modernization trend. Moderate for derived judgments about readiness, command architecture, internal program health, and future force trajectory because public reporting omits classified collection, detailed methodology, and PRC internal decision records.","theater":"Global","domain":"Source Packets","tags":["china","nuclear","and","missile","modernization","source","packet","collections","source-packets","strategic-weapons","2026-06-13t0250z-china-nuclear-missile-modernization-source-packet","source packet","global","source packets","wi-sourcepacket-china-stratweapons-2026-0001","2026-06-13t02:50:08z","high","for","official","public","identity","publication","date","stated","scope","broad","trend","moderate","derived","judgments","about","readiness","command","architecture","internal","program","health","future","force","trajectory","because","reporting","omits","classified","collection","detailed","methodology","prc","decision","records"]},{"title":"China/PLA Official Military And Security Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T0523Z-china-pla-official-military-security-source-baseline-packet.html","summary":"The China/PLA lane now needs a broad official-source spine in addition to the existing China assessments and China strategic-weapons packet. The DoD PRC military power report remains the main public U.S. defense source for PLA strategy, capability modernization, Taiwan pressure, South China Sea activity, defense spending, defense-industrial modernization, technology acquisition, and military-to-military contacts. ODNI provides the current public IC threat frame across China, Taiwan, cyber, space, WMD, South China Sea, and regional coercion. PRC official sources provide issuer-position evidence for how Beijing describes its defense policy, sovereignty claims, military reform, and national defense posture, but they should not be treated as independent verification of capability, intent, transparency, or restraint.","productId":"WI-SOURCEPACKET-CHINA-PLA-2026-0001","preparedUtc":"2026-06-14T05:23:13Z","cutoffUtc":"2026-06-14T05:23:13Z","confidence":"High for official source identity, DoD PRC report scope, ODNI threat-framing source identity, PRC white paper source identity, and existing WARLOCK-INDEX cross-product routing. Moderate for current PRC issuer-source completeness, Taiwan/ally cross-check completeness, defense budget interpretation, PLA readiness, defense-industrial output, cyber actor attribution, crisis decision-making, force employment, and implementation status because public sources are partial, politically framed, dynamic, and often constrained by classification, propaganda, access, and translation limits.","theater":"Collections","domain":"Source Packets","tags":["china","pla","official","military","and","security","source","baseline","packet","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t0523z-china-pla-official-military-security-source-baseline-packet","source packet","source packets","wi-sourcepacket-china-pla-2026-0001","2026-06-14t05:23:13z","high","for","identity","dod","prc","report","scope","odni","threat-framing","white","paper","existing","warlock-index","cross-product","routing","moderate","current","issuer-source","completeness","taiwan","ally","cross-check","defense","budget","interpretation","readiness","defense-industrial","output","cyber","actor","attribution","crisis","decision-making","force","employment","implementation","status","because","public","sources","are","partial","politically","framed","dynamic","often","constrained","by","classification","propaganda","access","translation","limits"]},{"title":"CIA, State, And NGA Foreign Government And Map Reference Packet","type":"Source Packet","path":"library/collections/source-packets/official-threat-source-baseline/2026-06-13T0831Z-cia-foreign-government-map-reference-packet.html","summary":"WARLOCK-INDEX should treat foreign government and map references as an orientation layer, not as a threat list. CIA World Leaders can anchor current foreign leadership and cabinet reference. CIA historical leadership snapshots can support dated-change context. The former CIA World Factbook should be handled as legacy reference after its February 2026 sunset. State Department country pages remain a necessary diplomatic-source family, but the current landing page needs manual refresh before it carries current claims. NGA public products and maps are useful for strategic geography, map-source provenance, and theater orientation.","productId":"WI-SOURCEPACKET-US-THREAT-2026-0002","preparedUtc":"2026-06-13T08:31:00Z","cutoffUtc":"2026-06-13T08:31:00Z","confidence":"High for CIA World Leaders identity, update cadence, and Factbook sunset status. High for NGA public products and map-download source-family identity. Moderate for State Department country-page recency because the current access check returned a public technical-difficulties response.","theater":"Collections","domain":"Source Packets","tags":["cia","state","and","nga","foreign","government","map","reference","packet","collections","source-packets","official-threat-source-baseline","2026-06-13t0831z-cia-foreign-government-map-reference-packet","source packet","source packets","wi-sourcepacket-us-threat-2026-0002","2026-06-13t08:31:00z","high","for","world","leaders","identity","update","cadence","factbook","sunset","status","public","products","map-download","source-family","moderate","department","country-page","recency","because","the","current","access","check","returned","technical-difficulties","response"]},{"title":"Denmark Official Defense, Security, And Arctic Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-16T0328Z-denmark-official-defense-security-arctic-source-packet.html","summary":"Denmark's official source lane should be treated as both a NATO/EU allied capacity lane and a High North/North Atlantic lane. The 2024-2033 Danish Defence Agreement provides the public planning spine: a ten-year framework, NATO spending commitment, force-development ambitions, conscription and personnel changes, and a reorientation toward the Kingdom of Denmark, neighboring regions, and international hotspots. That source is strong for issuer policy framing, but it is not delivery proof.","productId":"WI-SOURCEPACKET-DNK-ALLY-2026-0001","preparedUtc":"2026-06-16T03:28:00Z","cutoffUtc":"2026-06-16T03:27:43Z","confidence":"High for Danish Ministry of Defence source-family identity, 2024-2033 defense-agreement framing, NATO/EU/NORDEFCO routing, and Arctic/North Atlantic source identity. Moderate for capability delivery, readiness, Greenland/Faroe implementation, naval modernization, cyber implementation, and industrial output because those require follow-on budget, parliamentary, audit, procurement, armed-forces, Greenland, and Faroe Islands source refresh.","theater":"Arctic / High North","domain":"Source Packets","tags":["denmark","official","defense","security","and","arctic","source","packet","collections","source-packets","arctic-infrastructure","2026-06-16t0328z-denmark-official-defense-security-arctic-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-dnk-ally-2026-0001","2026-06-16t03:28:00z","2026-06-16t03:27:43z","high","for","danish","ministry","of","defence","source-family","identity","2024-2033","defense-agreement","framing","nato","eu","nordefco","routing","north","atlantic","moderate","capability","delivery","readiness","greenland","faroe","implementation","naval","modernization","cyber","industrial","output","because","those","require","follow-on","budget","parliamentary","audit","procurement","armed-forces","islands","refresh"]},{"title":"DoD 2025 To PRC Issuer-Language Claim Crosswalk","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T1927Z-dod-2025-prc-issuer-language-claim-crosswalk.html","summary":"The DoD 2025 report and PRC issuer-language sources should be read against one another, not blended. DoD 2025 is the current public U.S. defense assessment spine for China and the PLA. PRC State Council, MND, China Military Online, and Xinhua military-publication sources are issuer-perspective evidence for how Beijing publicly frames defense policy, sovereignty, military reform, cyber, space, information support, international security, and military diplomacy.","productId":"WI-SOURCEPACKET-CHINA-DOD-PRC-CROSSWALK-2026-0001","preparedUtc":"2026-06-14T19:27:19Z","cutoffUtc":"2026-06-14T19:27:19Z","confidence":"High for DoD 2025 section identity, State Council white-paper page identity, and accessible Xinhua publication identity. Moderate for PRC issuer-language completeness because direct PRC MND and China Military Online page capture remains access-caveated and Chinese-language originals require a separate terminology pass. Low for adjudicating contested claims without Taiwan, allied, legal, audit, technical, and independent research cross-checks.","theater":"Collections","domain":"Source Packets","tags":["dod","2025","to","prc","issuer-language","claim","crosswalk","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t1927z-dod-2025-prc-issuer-language-claim-crosswalk","source packet","source packets","wi-sourcepacket-china-dod-prc-crosswalk-2026-0001","2026-06-14t19:27:19z","high","for","section","identity","state","council","white-paper","page","and","accessible","xinhua","publication","moderate","completeness","because","direct","mnd","china","military","online","capture","remains","access-caveated","chinese-language","originals","require","separate","terminology","pass","low","adjudicating","contested","claims","without","taiwan","allied","legal","audit","technical","independent","research","cross-checks"]},{"title":"DoD/DIA China Military Power Extraction Map","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T0605Z-dod-dia-china-military-power-extraction-map.html","summary":"The DoD 2025 PRC military-power report is the current primary public U.S. defense source for China/PLA strategic and military modernization questions. It is strongest as a sectioned evidence router: national strategy, PLA strategy and capabilities, force employment, Taiwan pressure, South China Sea coercion, global influence, spending, industry, and emerging technology. The DoD 2024 report is the prior-year comparator for changes in emphasis, and DIA 2019 remains valuable as a historical baseline for older PLA modernization framing, but its force-structure and capability claims must be refreshed against newer sources.","productId":"WI-SOURCEPACKET-CHINA-DOD-DIA-2026-0001","preparedUtc":"2026-06-14T06:05:33Z","cutoffUtc":"2026-06-14T06:05:33Z","confidence":"High for the identity, public availability, and section structure of the DoD 2025 report, DoD 2024 report, and DIA 2019 baseline. Moderate for current analytic completeness because the public reports are unclassified products, omit sensitive sources and methods, and represent U.S. defense/intelligence framing. Lower for direct comparison to PRC issuer claims unless paired with PRC primary-source dates, translation status, and external corroboration.","theater":"Collections","domain":"Source Packets","tags":["dod","dia","china","military","power","extraction","map","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t0605z-dod-dia-china-military-power-extraction-map","source packet","source packets","wi-sourcepacket-china-dod-dia-2026-0001","2026-06-14t06:05:33z","high","for","the","identity","public","availability","and","section","structure","of","2025","report","2024","2019","baseline","moderate","current","analytic","completeness","because","reports","are","unclassified","products","omit","sensitive","sources","methods","represent","defense","intelligence","framing","lower","direct","comparison","to","prc","issuer","claims","unless","paired","with","primary-source","dates","translation","status","external","corroboration"]},{"title":"DPRK Strategic Weapons Source Packet","type":"Source Packet","path":"library/collections/source-packets/strategic-weapons/2026-06-13T2151Z-dprk-strategic-weapons-source-packet.html","summary":"The DPRK strategic-weapons lane connects U.S. homeland missile warning, ROK/Japan allied assurance, theater missile defense, WMD concern, cyber-enabled weapons funding, sanctions evasion, and Russia-war support. North Korea is not a great-power peer, but its nuclear and missile programs create a high-consequence strategic problem because they can affect U.S. homeland risk, extended deterrence credibility, peninsula crisis stability, Japan and ROK security, and nonproliferation norms.","productId":"WI-SOURCEPACKET-DPRK-STRATWEAPONS-2026-0001","preparedUtc":"2026-06-13T21:51:45Z","cutoffUtc":"2026-06-13T21:51:45Z","confidence":"High for official public source identity, DPRK strategic-weapons relevance, homeland missile relevance, ROK/Japan allied assurance relevance, UN sanctions baseline, and DPRK cyber-finance/WMD linkage as public-source research lanes. Moderate for current arsenal size, deployed readiness, command-and-control resilience, missile reliability, fissile-material production, Russia-DPRK transfer detail, and future test or signaling patterns because public sources omit classified intelligence, internal decision-making, and technical performance detail.","theater":"Global","domain":"Source Packets","tags":["dprk","strategic","weapons","source","packet","collections","source-packets","strategic-weapons","2026-06-13t2151z-dprk-strategic-weapons-source-packet","source packet","global","source packets","wi-sourcepacket-dprk-stratweapons-2026-0001","2026-06-13t21:51:45z","high","for","official","public","identity","relevance","homeland","missile","rok","japan","allied","assurance","un","sanctions","baseline","and","cyber-finance","wmd","linkage","as","public-source","research","lanes","moderate","current","arsenal","size","deployed","readiness","command-and-control","resilience","reliability","fissile-material","production","russia-dprk","transfer","detail","future","test","or","signaling","patterns","because","sources","omit","classified","intelligence","internal","decision-making","technical","performance"]},{"title":"EU Security And Defense Source Packet","type":"Source Packet","path":"library/collections/source-packets/nato-allied-capacity/2026-06-16T0330Z-eu-security-defense-source-packet.html","summary":"EU security-defense sources are essential for European allied analysis, but they are not interchangeable with NATO or national force evidence. The Strategic Compass provides an EU-level security and defense framework; EDIS and Readiness 2030 provide defense-industrial, capability-gap, procurement, and investment-source routing; EDIP and SAFE provide implementation/funding lanes; CSDP pages route missions and operations; and EU cyber, sanctions, and resilience source families support cross-domain analysis. Country-level force generation, readiness, delivery, and political implementation still require national sources.","productId":"WI-SOURCEPACKET-EU-ALLY-2026-0001","preparedUtc":"2026-06-16T03:30:00Z","cutoffUtc":"2026-06-16T03:27:43Z","confidence":"High for EU official source-family identity, Strategic Compass source identity, EDIS/Readiness 2030 source routing, and public EU defense-industrial-policy framing. Moderate for implementation, funding execution, member-state uptake, capability closure, military mobility, SAFE/EDIP disbursement, and defense-readiness evidence pending follow-on Commission, Council, Parliament, EDA, budget, legal, and national source refresh.","theater":"Collections","domain":"Source Packets","tags":["eu","security","and","defense","source","packet","collections","source-packets","nato-allied-capacity","2026-06-16t0330z-eu-security-defense-source-packet","source packet","source packets","wi-sourcepacket-eu-ally-2026-0001","2026-06-16t03:30:00z","2026-06-16t03:27:43z","high","for","official","source-family","identity","strategic","compass","edis","readiness","2030","routing","public","defense-industrial-policy","framing","moderate","implementation","funding","execution","member-state","uptake","capability","closure","military","mobility","safe","edip","disbursement","defense-readiness","evidence","pending","follow-on","commission","council","parliament","eda","budget","legal","national","refresh"]},{"title":"Europe, NATO, And Ukraine Map Reference Source Packet","type":"Source Packet","path":"library/collections/source-packets/theater-map-reference/2026-06-13T1938Z-europe-nato-ukraine-map-reference-source-packet.html","summary":"Europe, NATO, and Ukraine map references are high-risk for over-reading because static public maps sit close to an active war, alliance posture, and contested territory. WARLOCK-INDEX should use official public maps to answer narrow source questions: who published the map, what geographic frame does it show, what date or title does it carry, and what caveats are needed before using it in a strategic product?","productId":"WI-SOURCEPACKET-MAP-EUR-UKR-2026-0001","preparedUtc":"2026-06-13T19:38:00Z","cutoffUtc":"2026-06-13T19:38:00Z","confidence":"High for NGA public map-title identity for NATO Map 2024 and Ukraine Eastern Border Map 2023. High for NATO member-country page and NATO on the Map source identity. Moderate for State Ukraine and Russia country-area source-family use because current direct access checks returned HTTP 200 but exact page content should still be refreshed before dated diplomatic claims. Low to moderate for EUCOM and UN Geospatial current page use in this environment because direct access checks returned HTTP 403.","theater":"Collections","domain":"Source Packets","tags":["europe","nato","and","ukraine","map","reference","source","packet","collections","source-packets","theater-map-reference","2026-06-13t1938z-europe-nato-ukraine-map-reference-source-packet","source packet","source packets","wi-sourcepacket-map-eur-ukr-2026-0001","2026-06-13t19:38:00z","high","for","nga","public","map-title","identity","2024","eastern","border","2023","member-country","page","on","the","moderate","state","russia","country-area","source-family","use","because","current","direct","access","checks","returned","http","200","but","exact","content","should","still","be","refreshed","before","dated","diplomatic","claims","low","to","eucom","un","geospatial","in","this","environment","403"]},{"title":"Finland Official Defense, Security, And NATO Integration Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-14T0427Z-finland-official-defense-security-nato-integration-source-packet.html","summary":"Finland's official source lane is a high-value Nordic and High North allied baseline because Finnish sources pair a strong national-defense frame with a new NATO collective-defense integration frame. Ministry of Defence and Finnish Defence Forces pages establish that Finland is a NATO member, that national defense remains central, and that integration into NATO planning, exercises, capability development, command structures, and common defense continues after formal membership milestones. WARLOCK-INDEX should preserve that dual framing rather than treating NATO membership as a substitute for national Finnish defense evidence.","productId":"WI-SOURCEPACKET-FIN-ALLY-2026-0001","preparedUtc":"2026-06-14T04:27:32Z","cutoffUtc":"2026-06-14T04:27:32Z","confidence":"High for Finnish official source identity, NATO membership and integration framing, DCA source identity, Nordic defence cooperation source identity, Finnish Defence Forces mission and NATO integration source routing, and Supo/NCSC/NESA source-family identity. Moderate for force delivery, investment execution, Forward Land Forces implementation, MCLCC/host-nation support implementation, cyber maturity, industrial output, and readiness evidence because those require follow-on budget, parliamentary, audit, procurement, armed-forces, NATO, and agency implementation sources.","theater":"Arctic / High North","domain":"Source Packets","tags":["finland","official","defense","security","and","nato","integration","source","packet","collections","source-packets","arctic-infrastructure","2026-06-14t0427z-finland-official-defense-security-nato-integration-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-fin-ally-2026-0001","2026-06-14t04:27:32z","high","for","finnish","identity","membership","framing","dca","nordic","defence","cooperation","forces","mission","routing","supo","ncsc","nesa","source-family","moderate","force","delivery","investment","execution","forward","land","implementation","mclcc","host-nation","support","cyber","maturity","industrial","output","readiness","evidence","because","those","require","follow-on","budget","parliamentary","audit","procurement","armed-forces","agency","sources"]},{"title":"France Official Defense And Security Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/nato-allied-capacity/2026-06-14T0208Z-france-official-defense-security-source-baseline-packet.html","summary":"France's official-source lane should be treated as a nuclear-armed European ally file, a Euro-Atlantic defense file, and a sovereignty/industrial-base file. The current top-level source is the 2025 update to the National Strategic Review, which SGDSN says was commanded by the President and complements the 2022 review. The English courtesy translation frames the updated 2030 ambition around nuclear deterrence, national resilience, an economy prepared for war, cyber resilience, France as a reliable Euro-Atlantic ally, European strategic autonomy, sovereignty partnerships, hybrid fields, military operations, and science/technology.","productId":"WI-SOURCEPACKET-FRA-ALLY-2026-0001","preparedUtc":"2026-06-14T02:08:02Z","cutoffUtc":"2026-06-14T02:08:02Z","confidence":"High for official French source identity, RNS 2025 and 2022 strategic framing, LPM 2024-2030 legal/budget architecture, Élysée deterrence doctrine source identity, and ANSSI cyber-threat source identity. Moderate for Ministry of Armed Forces implementation, procurement delivery, force readiness, industrial output, and Indo-Pacific posture evidence because defense-ministry dynamic pages were not reliably accessible from this environment and require direct official document refresh.","theater":"Collections","domain":"Source Packets","tags":["france","official","defense","and","security","source","baseline","packet","collections","source-packets","nato-allied-capacity","2026-06-14t0208z-france-official-defense-security-source-baseline-packet","source packet","source packets","wi-sourcepacket-fra-ally-2026-0001","2026-06-14t02:08:02z","high","for","french","identity","rns","2025","2022","strategic","framing","lpm","2024-2030","legal","budget","architecture","lys","deterrence","doctrine","anssi","cyber-threat","moderate","ministry","of","armed","forces","implementation","procurement","delivery","force","readiness","industrial","output","indo-pacific","posture","evidence","because","defense-ministry","dynamic","pages","were","not","reliably","accessible","from","this","environment","require","direct","document","refresh"]},{"title":"Germany Official Defense And Security Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/nato-allied-capacity/2026-06-14T0219Z-germany-official-defense-security-source-baseline-packet.html","summary":"Germany's official-source lane should be treated as a Euro-Atlantic allied capacity file, a NATO/EU burden-sharing file, a defense-investment and industrial-capacity file, and an integrated-security/resilience file. The National Security Strategy provides the whole-of-government frame: Germany describes security as robust, resilient, and sustainable; identifies Russia as the most significant threat to peace and security in the Euro-Atlantic area; treats China as partner, competitor, and systemic rival; and ties NATO, EU, Bundeswehr, critical infrastructure, cyber, civil protection, energy, raw materials, and supply-chain resilience into one integrated-security concept.","productId":"WI-SOURCEPACKET-DEU-ALLY-2026-0001","preparedUtc":"2026-06-14T02:19:34Z","cutoffUtc":"2026-06-14T02:19:34Z","confidence":"High for German official source identity, National Security Strategy framing, Defence Policy Guidelines source identity and defense-policy framing, BMVg 2026 investment page identity, and China Strategy source identity. Moderate for implementation, readiness, procurement delivery, industrial output, cyber-agency coverage, space policy, and civil-preparedness evidence because those require follow-on direct budget, parliamentary, audit, BSI/BMI, Bundeswehr, and defense-ministry document collection.","theater":"Collections","domain":"Source Packets","tags":["germany","official","defense","and","security","source","baseline","packet","collections","source-packets","nato-allied-capacity","2026-06-14t0219z-germany-official-defense-security-source-baseline-packet","source packet","source packets","wi-sourcepacket-deu-ally-2026-0001","2026-06-14t02:19:34z","high","for","german","identity","national","strategy","framing","defence","policy","guidelines","defense-policy","bmvg","2026","investment","page","china","moderate","implementation","readiness","procurement","delivery","industrial","output","cyber-agency","coverage","space","civil-preparedness","evidence","because","those","require","follow-on","direct","budget","parliamentary","audit","bsi","bmi","bundeswehr","defense-ministry","document","collection"]},{"title":"Iceland Official Security, Defense, And NATO Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-16T0329Z-iceland-official-security-defense-nato-source-packet.html","summary":"Iceland is a small but strategically important North Atlantic allied source lane. Its public source treatment should not be forced into a conventional standing-military template. The Ministry for Foreign Affairs is the primary government source family for national security and defense policy, while the Icelandic Coast Guard, NATO, and allied air-policing sources carry much of the public operational-context routing. This creates an unusual source stack: foreign-ministry policy, Coast Guard security/defense functions, NATO air-policing and integrated air/missile defense context, and Arctic/North Atlantic geography.","productId":"WI-SOURCEPACKET-ISL-ALLY-2026-0001","preparedUtc":"2026-06-16T03:29:00Z","cutoffUtc":"2026-06-16T03:27:43Z","confidence":"High for Icelandic government and Coast Guard source-family identity and for Iceland's NATO/High North source-routing role. Moderate for direct page-level claims in this pass because several Icelandic official pages require follow-on browser/manual refresh and document-level verification. Moderate for capability, infrastructure, air-policing, resilience, and implementation evidence pending direct Coast Guard, parliamentary, NATO, Keflavik, cyber, and budget-source refresh.","theater":"Arctic / High North","domain":"Source Packets","tags":["iceland","official","security","defense","and","nato","source","packet","collections","source-packets","arctic-infrastructure","2026-06-16t0329z-iceland-official-security-defense-nato-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-isl-ally-2026-0001","2026-06-16t03:29:00z","2026-06-16t03:27:43z","high","for","icelandic","government","coast","guard","source-family","identity","north","source-routing","role","moderate","direct","page-level","claims","in","this","pass","because","several","pages","require","follow-on","browser","manual","refresh","document-level","verification","capability","infrastructure","air-policing","resilience","implementation","evidence","pending","parliamentary","keflavik","cyber","budget-source"]},{"title":"India/Quad Strategic-Partner Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-allied-posture/2026-06-16T0512Z-india-quad-strategic-partner-source-packet.html","summary":"The India/Quad lane belongs in WARLOCK-INDEX as a strategic-partner source stack, not as a treaty-allied source stack. The Quad sources identify Australia, India, Japan, and the United States as partners working through diplomatic, maritime, economic-security, technology, health, and emergency response initiatives across the Indo-Pacific. They do not create NATO-style collective-defense evidence, automatic crisis behavior, basing rights, readiness proof, or operational commitments.","productId":"WI-SOURCEPACKET-INDOPAC-PARTNER-2026-0001","preparedUtc":"2026-06-16T05:12:39Z","cutoffUtc":"2026-06-16T05:12:39Z","confidence":"High for Quad partner identity, official Quad source-family routing, May 2026 New Delhi initiative identity, iCET/INDUS-X source identity, and the requirement to keep India/Quad partner terminology separate from treaty-allied lanes. Moderate for India-specific defense implementation, budget execution, force-delivery, maritime capacity, critical minerals execution, and technology-delivery claims pending direct Indian defense, parliamentary, budget, audit, and ministry document refresh.","theater":"Collections","domain":"Source Packets","tags":["india","quad","strategic-partner","source","packet","collections","source-packets","indo-pacific-allied-posture","2026-06-16t0512z-india-quad-strategic-partner-source-packet","source packet","source packets","wi-sourcepacket-indopac-partner-2026-0001","2026-06-16t05:12:39z","high","for","partner","identity","official","source-family","routing","may","2026","new","delhi","initiative","icet","indus-x","and","the","requirement","to","keep","terminology","separate","from","treaty-allied","lanes","moderate","india-specific","defense","implementation","budget","execution","force-delivery","maritime","capacity","critical","minerals","technology-delivery","claims","pending","direct","indian","parliamentary","audit","ministry","document","refresh"]},{"title":"Indo-Pacific Adversary Posture Source Packets","type":"Directory","path":"library/collections/source-packets/indo-pacific-adversary-posture/index.html","summary":"Indo-Pacific Adversary Posture Source Packets organize official and high-reliability public sources on adversary and competitor posture across the regional research lane.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Indo Pacific Adversary Posture","tags":["indo-pacific","adversary","posture","source","packets","collections","source-packets","indo-pacific-adversary-posture","readme","directory","indo pacific adversary posture"]},{"title":"Indo-Pacific Allied Posture Official Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-allied-posture/2026-06-13T0316Z-indo-pacific-allied-posture-official-source-baseline-packet.html","summary":"Indo-Pacific allied posture is best treated as a networked source problem, not as a single bilateral file. The White House Camp David documents provide the official public baseline for U.S.-Japan-ROK trilateral coordination across regional security, DPRK missile warning, maritime security, economic security, technology standards, and consultation. The Washington Declaration provides a separate U.S.-ROK extended-deterrence and Nuclear Consultative Group baseline. The AUKUS and EDCA files anchor the Australia and Philippines access, industrial, undersea, and archipelagic posture lanes already present in the WARLOCK-INDEX allied profile.","productId":"WI-SOURCEPACKET-INDOPAC-ALLY-2026-0001","preparedUtc":"2026-06-13T03:16:36Z","cutoffUtc":"2026-06-13T03:16:36Z","confidence":"High for official source identity, declared alliance and trilateral frameworks, and public diplomatic-security commitments. Moderate for implementation because official public statements do not reveal classified readiness, contingency planning, access arrangements, stockpile depth, or political behavior under crisis conditions.","theater":"Collections","domain":"Source Packets","tags":["indo-pacific","allied","posture","official","source","baseline","packet","collections","source-packets","indo-pacific-allied-posture","2026-06-13t0316z-indo-pacific-allied-posture-official-source-baseline-packet","source packet","source packets","wi-sourcepacket-indopac-ally-2026-0001","2026-06-13t03:16:36z","high","for","identity","declared","alliance","and","trilateral","frameworks","public","diplomatic-security","commitments","moderate","implementation","because","statements","do","not","reveal","classified","readiness","contingency","planning","access","arrangements","stockpile","depth","or","political","behavior","under","crisis","conditions"]},{"title":"Indo-Pacific Allied Posture Source Packets","type":"Directory","path":"library/collections/source-packets/indo-pacific-allied-posture/index.html","summary":"Indo-Pacific Allied Posture Source Packets organize official public sources on regional allies and partners for later assessments.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Indo Pacific Allied Posture","tags":["indo-pacific","allied","posture","source","packets","collections","source-packets","indo-pacific-allied-posture","readme","directory","indo pacific allied posture"]},{"title":"Indo-Pacific And Taiwan Map Reference Source Packet","type":"Source Packet","path":"library/collections/source-packets/theater-map-reference/2026-06-13T1810Z-indo-pacific-taiwan-map-reference-source-packet.html","summary":"The Indo-Pacific/Taiwan map lane should use public maps as orientation anchors, not as planning tools. NGA's public Taiwan 2024 map can anchor a static map reference. USINDOPACOM's Area of Responsibility page can anchor U.S. command-area framing. The Taiwan Relations Act can anchor U.S. statutory policy context, but it is not a map source. State and AIT pages remain required diplomatic-source families, but current access checks returned technical-difficulties/forbidden responses and should be manually refreshed before current-use claims.","productId":"WI-SOURCEPACKET-MAP-INDOPAC-2026-0001","preparedUtc":"2026-06-13T18:10:00Z","cutoffUtc":"2026-06-13T18:10:00Z","confidence":"High for NGA public-release map identity and USINDOPACOM public command-area framing. High for U.S. Code Taiwan Relations Act statutory text. Moderate for State and AIT current page routing because current access checks returned public technical-difficulties responses.","theater":"Collections","domain":"Source Packets","tags":["indo-pacific","and","taiwan","map","reference","source","packet","collections","source-packets","theater-map-reference","2026-06-13t1810z-indo-pacific-taiwan-map-reference-source-packet","source packet","source packets","wi-sourcepacket-map-indopac-2026-0001","2026-06-13t18:10:00z","high","for","nga","public-release","identity","usindopacom","public","command-area","framing","code","relations","act","statutory","text","moderate","state","ait","current","page","routing","because","access","checks","returned","technical-difficulties","responses"]},{"title":"Iran WMD And Missile-Relevance Source Packet","type":"Source Packet","path":"library/collections/source-packets/strategic-weapons/2026-06-13T2203Z-iran-wmd-missile-relevance-source-packet.html","summary":"Iran belongs in the strategic-weapons file as a WMD-relevant, missile-relevant, UAS-proliferation, regional-deterrence, and sanctions/nonproliferation actor. It should not be coded as a confirmed nuclear weapons state in current WARLOCK-INDEX language. The stronger formulation is that Iran is a degraded and stressed regional adversary with elevated nuclear-obligation uncertainty, missile and space-launch relevance, CBW concern in public U.S. sources, regional missile and UAS effects, and cross-theater Russia-support relevance.","productId":"WI-SOURCEPACKET-IRAN-WMDMISSILE-2026-0001","preparedUtc":"2026-06-13T22:03:29Z","cutoffUtc":"2026-06-13T22:03:29Z","confidence":"High for official public source identity, Iran strategic-weapons relevance, missile and UAS relevance, UN Security Council legal-diplomatic baseline, and public U.S. policy framing. Moderate for current nuclear-material status, infrastructure damage and recovery, leadership intent, IAEA access durability, CBW program status, missile production recovery, Russia-Iran transfer detail, and future negotiation trajectory because public sources omit classified evidence, technical condition, and internal Iranian decision-making.","theater":"Global","domain":"Source Packets","tags":["iran","wmd","and","missile-relevance","source","packet","collections","source-packets","strategic-weapons","2026-06-13t2203z-iran-wmd-missile-relevance-source-packet","source packet","global","source packets","wi-sourcepacket-iran-wmdmissile-2026-0001","2026-06-13t22:03:29z","high","for","official","public","identity","relevance","missile","uas","un","security","council","legal-diplomatic","baseline","policy","framing","moderate","current","nuclear-material","status","infrastructure","damage","recovery","leadership","intent","iaea","access","durability","cbw","program","production","russia-iran","transfer","detail","future","negotiation","trajectory","because","sources","omit","classified","evidence","technical","condition","internal","iranian","decision-making"]},{"title":"Japan Official Defense And Security Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-allied-posture/2026-06-14T0147Z-japan-official-defense-security-source-baseline-packet.html","summary":"Japan's official-source lane should be treated as a whole-of-government Indo-Pacific allied posture file. The Ministry of Defense defense-policy page anchors the 2022 three strategic documents: the National Security Strategy, National Defense Strategy, and Defense Buildup Program. Those documents connect Japan's severe regional security environment, the Japan-U.S. Alliance, like-minded-country cooperation, cross-domain capabilities, defense production and technology base, space, cyber, integrated air and missile defense, unmanned systems, sustainment, personnel, and civil protection.","productId":"WI-SOURCEPACKET-JPN-ALLY-2026-0001","preparedUtc":"2026-06-14T01:47:45Z","cutoffUtc":"2026-06-14T01:47:45Z","confidence":"High for official Japanese source identity, source family routing, and declared defense/security strategy framing. Moderate for implementation, readiness, procurement delivery, technology maturity, cyber resilience, alliance operational integration, and crisis behavior because public strategy, budget, and annual documents do not prove classified capability, plans, or performance.","theater":"Collections","domain":"Source Packets","tags":["japan","official","defense","and","security","source","baseline","packet","collections","source-packets","indo-pacific-allied-posture","2026-06-14t0147z-japan-official-defense-security-source-baseline-packet","source packet","source packets","wi-sourcepacket-jpn-ally-2026-0001","2026-06-14t01:47:45z","high","for","japanese","identity","family","routing","declared","strategy","framing","moderate","implementation","readiness","procurement","delivery","technology","maturity","cyber","resilience","alliance","operational","integration","crisis","behavior","because","public","budget","annual","documents","do","not","prove","classified","capability","plans","or","performance"]},{"title":"Multilateral Strategic Stability Source Packet","type":"Source Packet","path":"library/collections/source-packets/strategic-weapons/2026-06-13T2216Z-multilateral-strategic-stability-source-packet.html","summary":"Multilateral strategic stability is now a format problem as much as a weapons problem. The New START framework was bilateral, but the public strategic environment is increasingly shaped by Russia, China, the United States, NATO, DPRK, Iran-related WMD and missile concerns, advanced delivery systems, counterspace, cyber, missile defense, and conventional-nuclear ambiguity. The official-source record supports a careful distinction between treaty obligation, political statement, diplomatic venue, transparency measure, verification mechanism, actor capability trend, and strategic-stability effect.","productId":"WI-SOURCEPACKET-MULTISTABILITY-2026-0001","preparedUtc":"2026-06-13T22:16:47Z","cutoffUtc":"2026-06-13T22:16:47Z","confidence":"High for source identity, treaty baseline, official P5 statement language, NATO public posture, and U.S. public arms-control framing. Moderate for future multilateral strategic-stability prospects, because participation, scope, verification, and political durability depend on state decisions and incomplete public evidence.","theater":"Global","domain":"Source Packets","tags":["multilateral","strategic","stability","source","packet","collections","source-packets","strategic-weapons","2026-06-13t2216z-multilateral-strategic-stability-source-packet","source packet","global","source packets","wi-sourcepacket-multistability-2026-0001","2026-06-13t22:16:47z","high","for","identity","treaty","baseline","official","p5","statement","language","nato","public","posture","and","arms-control","framing","moderate","future","strategic-stability","prospects","because","participation","scope","verification","political","durability","depend","on","state","decisions","incomplete","evidence"]},{"title":"NATO Allied Capacity Official Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/nato-allied-capacity/2026-06-13T0243Z-nato-allied-capacity-official-source-baseline-packet.html","summary":"NATO allied capacity analysis requires a source stack rather than a single headline metric. Summit declarations identify consensus political commitments; the 5 percent and funding pages define spending categories and burden-sharing logic; the defense industry page links deterrence to production and interoperability; the resilience page makes civil preparedness part of Article 3 capacity; the cyber page frames cyber defence as a core deterrence and resilience issue; and the Ukraine support page shows how aid, training, coordination, and Alliance assurance interact under war pressure. Together, these sources support a strategic assessment of NATO as a capacity network, but they do not prove national readiness or industrial conversion by themselves.","productId":"WI-SOURCEPACKET-NATO-ALLY-2026-0001","preparedUtc":"2026-06-13T02:43:41Z","cutoffUtc":"2026-06-13T02:43:41Z","confidence":"High for official NATO source identity, declared summit commitments, public institutional framing, and source relevance. Moderate for implementation assessment because official NATO public pages do not fully reveal readiness, national caveats, classified capability targets, stockpile depth, industrial bottlenecks, or political durability.","theater":"Collections","domain":"Source Packets","tags":["nato","allied","capacity","official","source","baseline","packet","collections","source-packets","nato-allied-capacity","2026-06-13t0243z-nato-allied-capacity-official-source-baseline-packet","source packet","source packets","wi-sourcepacket-nato-ally-2026-0001","2026-06-13t02:43:41z","high","for","identity","declared","summit","commitments","public","institutional","framing","and","relevance","moderate","implementation","assessment","because","pages","do","not","fully","reveal","readiness","national","caveats","classified","capability","targets","stockpile","depth","industrial","bottlenecks","or","political","durability"]},{"title":"NATO Allied Capacity Source Packets","type":"Directory","path":"library/collections/source-packets/nato-allied-capacity/index.html","summary":"NATO Allied Capacity Source Packets organize public evidence on allied capacity, burden-sharing, investment, resilience, Ukraine support, cyber defence, and implementation signals.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"NATO Allied Capacity","tags":["nato","allied","capacity","source","packets","collections","source-packets","nato-allied-capacity","readme","directory","nato allied capacity"]},{"title":"NORAD Modernization Implementation Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-16T0221Z-norad-modernization-implementation-source-packet.html","summary":"NORAD modernization is now mature enough in public official sources to support a dedicated implementation-source lane. Canada has published a project-timeline fact sheet, a funding fact sheet, departmental planning language, and budget chapters that separate modernization into surveillance, command/control and communications, air weapons, infrastructure/support, and science/technology investment areas. NORAD and USNORTHCOM sources provide the binational mission and strategy frame; the 2024 DoD Arctic Strategy provides the U.S. Arctic and domain-awareness cross-check.","productId":"WI-SOURCEPACKET-NORAD-MOD-2026-0001","preparedUtc":"2026-06-16T02:21:36Z","cutoffUtc":"2026-06-16T02:21:36Z","confidence":"High for official public source identity, investment category names, declared implementation-source architecture, and mission-frame routing. Moderate for delivery evidence, schedule execution, project maturity, cost stability, readiness, operational effect, and system performance because public strategy, budget, and project-timeline pages do not independently prove fielded capability.","theater":"Arctic / High North","domain":"Source Packets","tags":["norad","modernization","implementation","source","packet","collections","source-packets","arctic-infrastructure","2026-06-16t0221z-norad-modernization-implementation-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-norad-mod-2026-0001","2026-06-16t02:21:36z","high","for","official","public","identity","investment","category","names","declared","implementation-source","architecture","and","mission-frame","routing","moderate","delivery","evidence","schedule","execution","project","maturity","cost","stability","readiness","operational","effect","system","performance","because","strategy","budget","project-timeline","pages","do","not","independently","prove","fielded","capability"]},{"title":"Norway Official Defense, Security, And High North Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-14T0319Z-norway-official-defense-security-high-north-source-packet.html","summary":"Norway's official source lane should be treated as both a High North allied defense file and a whole-of-society security/resilience file. The long-term defense plan establishes the public modernization frame through 2036 and links maritime, land, air, home guard, personnel, and alliance obligations. The 2026 acquisition plan and industrial-capacity roadmap create follow-on source lanes for procurement, defense industry, supply security, and implementation, but they remain planning and routing evidence until checked against budgets, contracts, Storting decisions, audit material, and delivery records.","productId":"WI-SOURCEPACKET-NOR-ALLY-2026-0001","preparedUtc":"2026-06-14T03:19:09Z","cutoffUtc":"2026-06-14T03:19:09Z","confidence":"High for Norwegian official source identity, long-term defense-plan framing, public acquisition source identity, 2026 public threat/risk source routing, NSM protective-security role, and Nordic defense cooperation source identity. Moderate for delivery, force-growth, industrial-output, drone implementation, cyber/resilience implementation, and High North readiness evidence because those require follow-on budget, Storting, audit, procurement, armed-forces, and agency-source refresh.","theater":"Arctic / High North","domain":"Source Packets","tags":["norway","official","defense","security","and","high","north","source","packet","collections","source-packets","arctic-infrastructure","2026-06-14t0319z-norway-official-defense-security-high-north-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-nor-ally-2026-0001","2026-06-14t03:19:09z","for","norwegian","identity","long-term","defense-plan","framing","public","acquisition","2026","threat","risk","routing","nsm","protective-security","role","nordic","cooperation","moderate","delivery","force-growth","industrial-output","drone","implementation","cyber","resilience","readiness","evidence","because","those","require","follow-on","budget","storting","audit","procurement","armed-forces","agency-source","refresh"]},{"title":"Official U.S. Threat Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/official-threat-source-baseline/2026-06-13T0559Z-official-us-threat-source-baseline-packet.html","summary":"WARLOCK-INDEX now has enough official U.S. source structure to treat threat coverage as a disciplined source-collection problem rather than a loose list of adversaries. The correct model is an agency-source lattice: ODNI for public IC-wide threat framing; CIA for foreign leadership and legacy country reference; FBI for terrorism, counterintelligence, cyber, WMD, and criminal program framing; DHS/CISA for homeland and infrastructure risk; State and Treasury for designations, terrorism, sanctions, and illicit finance; DEA, ATF, CBP, Coast Guard, and DOJ for public law-enforcement source streams; and NGA or CIA map products for strategic geographic orientation.","productId":"WI-SOURCEPACKET-US-THREAT-2026-0001","preparedUtc":"2026-06-13T05:59:00Z","cutoffUtc":"2026-06-13T05:59:00Z","confidence":"High for source identity where current official pages or stable agency product families are identified. Moderate for current document recency across dynamic agency pages because some public URLs change, block automated verification, or point to product families rather than a single static PDF.","theater":"Collections","domain":"Source Packets","tags":["official","threat","source","baseline","packet","collections","source-packets","official-threat-source-baseline","2026-06-13t0559z-official-us-threat-source-baseline-packet","source packet","source packets","wi-sourcepacket-us-threat-2026-0001","2026-06-13t05:59:00z","high","for","identity","where","current","pages","or","stable","agency","product","families","are","identified","moderate","document","recency","across","dynamic","because","some","public","urls","change","block","automated","verification","point","to","rather","than","single","static","pdf"]},{"title":"Official U.S. Threat Source Baseline Source Packets","type":"Directory","path":"library/collections/source-packets/official-threat-source-baseline/index.html","summary":"Official U.S. Threat Source Baseline packets organize public intelligence, homeland-security, law-enforcement, sanctions, border, maritime, cyber, and geospatial reference sources.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Official Threat Source Baseline","tags":["official","threat","source","baseline","packets","collections","source-packets","official-threat-source-baseline","readme","directory","official threat source baseline"]},{"title":"Philippines And South China Sea Map Reference Source Packet","type":"Source Packet","path":"library/collections/source-packets/theater-map-reference/2026-06-13T1856Z-philippines-south-china-sea-map-reference-source-packet.html","summary":"The Philippines and South China Sea map lane needs four separate layers: map orientation, issuer language, legal-source provenance, and threat or posture evidence. Public maps can orient the reader to the region and record publisher language, but they cannot prove sovereignty, control, intent, military access, basing availability, coercion, or operational feasibility.","productId":"WI-SOURCEPACKET-MAP-SCS-2026-0001","preparedUtc":"2026-06-13T18:56:00Z","cutoffUtc":"2026-06-13T18:56:00Z","confidence":"High for PCA case metadata, USINDOPACOM public command-area framing, and State Limits in the Seas source-family identity. High for NAMRIA as the Philippine national mapping source family. Moderate for exact Philippine Official Gazette page refresh because current direct access checks returned an access challenge instead of page content. Moderate for exact NAMRIA map-product use until specific map or catalog pages are refreshed and captured.","theater":"Collections","domain":"Source Packets","tags":["philippines","and","south","china","sea","map","reference","source","packet","collections","source-packets","theater-map-reference","2026-06-13t1856z-philippines-south-china-sea-map-reference-source-packet","source packet","source packets","wi-sourcepacket-map-scs-2026-0001","2026-06-13t18:56:00z","high","for","pca","case","metadata","usindopacom","public","command-area","framing","state","limits","in","the","seas","source-family","identity","namria","as","philippine","national","mapping","family","moderate","exact","official","gazette","page","refresh","because","current","direct","access","checks","returned","an","challenge","instead","of","content","map-product","use","until","specific","or","catalog","pages","are","refreshed","captured"]},{"title":"PLA Services And Arms Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T1933Z-pla-services-and-arms-source-packet.html","summary":"China/PLA analysis now needs a stable service-and-arm routing layer. DoD 2025 is the current public U.S. defense anchor for PLA strategy, capability lanes, C4ISR, cyber, space, nuclear, Taiwan, South China Sea, paramilitary forces, and defense-industrial topics. DIA 2019 remains useful as a historical baseline, but it predates the 2024 reorganization that PRC official-media sources describe through a four-service and four-arm taxonomy.","productId":"WI-SOURCEPACKET-CHINA-PLA-SERVICES-ARMS-2026-0001","preparedUtc":"2026-06-14T19:33:34Z","cutoffUtc":"2026-06-14T19:33:34Z","confidence":"High for DoD 2025 section identity, DIA 2019 historical-baseline identity, and accessible Xinhua publication identity. Moderate for current service/arm taxonomy because the 2024 PRC official-media source family is accessible through Xinhua and source pointers, but direct MND/China Military archive capture remains access-caveated. Lower for force readiness, command effectiveness, operational performance, service-specific capability, and wartime logistics because public sources are partial, politically framed, dynamic, and constrained by classification and propaganda limits.","theater":"Collections","domain":"Source Packets","tags":["pla","services","and","arms","source","packet","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t1933z-pla-services-and-arms-source-packet","source packet","source packets","wi-sourcepacket-china-pla-services-arms-2026-0001","2026-06-14t19:33:34z","high","for","dod","2025","section","identity","dia","2019","historical-baseline","accessible","xinhua","publication","moderate","current","service","arm","taxonomy","because","the","2024","prc","official-media","family","is","through","pointers","but","direct","mnd","china","military","archive","capture","remains","access-caveated","lower","force","readiness","command","effectiveness","operational","performance","service-specific","capability","wartime","logistics","public","sources","are","partial","politically","framed","dynamic","constrained","by","classification","propaganda","limits"]},{"title":"PRC Cyber And Critical Infrastructure Defensive Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T1956Z-prc-cyber-critical-infrastructure-defensive-source-packet.html","summary":"PRC cyber is now a dedicated defensive source lane rather than a broad \"future cyber packet\" queue item. ODNI 2026 provides the current public IC strategic frame: China is described as the most active and persistent cyber threat to U.S. government, private-sector, and critical-infrastructure networks, while multiple state and nonstate actors can pre-position or carry out disruptive activity against critical infrastructure. DoD 2025 provides the military-power frame: PLA cyber activity is tied to crisis and conflict relevance, defense and civilian critical-infrastructure disruption, and allied interoperability concerns.","productId":"WI-SOURCEPACKET-CHINA-CYBER-CI-2026-0001","preparedUtc":"2026-06-14T19:56:06Z","cutoffUtc":"2026-06-14T19:56:06Z","confidence":"High for ODNI 2026 cyber threat framing, DoD 2025 PLA cyber section identity, DOJ January 31, 2024 disruption source identity, State Council cyberspace-governance issuer-source identity, and existing WARLOCK-INDEX cyber baseline routing. Moderate for specific CISA, NSA, FBI, and allied advisory page-level extraction because some advisory URLs are captured through source-family routing and DOJ cross-links rather than full direct page content in this environment. Lower for actor tasking, intent, access persistence, sector-specific disruption severity, crisis timing, and private-sector victim completeness because public cyber sources are partial, defensive, dynamic, attribution-sensitive, and often deliberately non-exhaustive.","theater":"Collections","domain":"Source Packets","tags":["prc","cyber","and","critical","infrastructure","defensive","source","packet","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t1956z-prc-cyber-critical-infrastructure-defensive-source-packet","source packet","source packets","wi-sourcepacket-china-cyber-ci-2026-0001","2026-06-14t19:56:06z","high","for","odni","2026","threat","framing","dod","2025","pla","section","identity","doj","january","31","2024","disruption","state","council","cyberspace-governance","issuer-source","existing","warlock-index","baseline","routing","moderate","specific","cisa","nsa","fbi","allied","advisory","page-level","extraction","because","some","urls","are","captured","through","source-family","cross-links","rather","than","full","direct","page","content","in","this","environment","lower","actor","tasking","intent","access","persistence","sector-specific","severity","crisis","timing","private-sector","victim","completeness","public","sources","partial","dynamic","attribution-sensitive","often","deliberately","non-exhaustive"]},{"title":"PRC MND And PLA Official-Media Dated Capture Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T1927Z-prc-mnd-pla-official-media-dated-capture-packet.html","summary":"The PRC MND and PLA official-media lane is now usable as a dated issuer-source capture, but with explicit access caveats. The most reliable direct content in this pass is the April 19, 2024 Xinhua publication set: one item carries a PRC defense spokesperson's description of the Information Support Force and the PLA's revised service/arm taxonomy, and the other records the establishment ceremony, party-command language, direct CMC leadership, and cancellation of the Strategic Support Force designation.","productId":"WI-SOURCEPACKET-CHINA-MND-PLA-MEDIA-2026-0001","preparedUtc":"2026-06-14T19:27:19Z","cutoffUtc":"2026-06-14T19:27:19Z","confidence":"High for the identity and publication timestamp of the accessible Xinhua April 19, 2024 items and State Council white-paper routing pages. Moderate for source-family identity of PRC MND and China Military Online because the source families are official/public but direct fetches of current MND and China Military pages were unstable in this pass. Low for independent capability, readiness, legality, restraint, or intent claims unless corroborated by DoD, ODNI, Taiwan, allied, legal, audit, or research sources.","theater":"Collections","domain":"Source Packets","tags":["prc","mnd","and","pla","official-media","dated","capture","packet","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t1927z-prc-mnd-pla-official-media-dated-capture-packet","source packet","source packets","wi-sourcepacket-china-mnd-pla-media-2026-0001","2026-06-14t19:27:19z","high","for","the","identity","publication","timestamp","of","accessible","xinhua","april","19","2024","items","state","council","white-paper","routing","pages","moderate","source-family","china","military","online","because","source","families","are","official","public","but","direct","fetches","current","were","unstable","in","this","pass","low","independent","capability","readiness","legality","restraint","or","intent","claims","unless","corroborated","by","dod","odni","taiwan","allied","legal","audit","research","sources"]},{"title":"PRC Official Doctrine And Issuer-Language Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T0537Z-prc-official-doctrine-issuer-language-source-packet.html","summary":"PRC official doctrine and issuer-language sources are necessary for China/PLA research, but they are a different evidence class from U.S., Taiwan, allied, legal, cyber-advisory, audit, or independent research sources. The State Council/SCIO white-paper lane is useful for identifying Beijing's public language around national defense, sovereignty, \"defensive\" posture, expenditure, military reform, cyberspace governance, BeiDou, counterterrorism, and global-order narratives. Those pages are authoritative for what the PRC publicly claims or releases; they are not independent verification that those claims are complete, neutral, lawful, transparent, peaceful, or accurate.","productId":"WI-SOURCEPACKET-CHINA-ISSUER-2026-0001","preparedUtc":"2026-06-14T05:37:41Z","cutoffUtc":"2026-06-14T05:37:41Z","confidence":"High for accessible State Council English white-paper page identity, publication dates shown on accessed pages, and source-family routing. Moderate for document-level completeness because some pages point to attachments rather than exposing the full attachment text in this environment. Moderate to low for PRC MND and China Military Online current-page extraction because those source families require later direct access and dated capture. Low for independent verification of PRC claims unless corroborated by DoD, ODNI, Taiwan, allied, legal, audit, research, or other independent sources.","theater":"Collections","domain":"Source Packets","tags":["prc","official","doctrine","and","issuer-language","source","packet","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t0537z-prc-official-doctrine-issuer-language-source-packet","source packet","source packets","wi-sourcepacket-china-issuer-2026-0001","2026-06-14t05:37:41z","high","for","accessible","state","council","english","white-paper","page","identity","publication","dates","shown","on","accessed","pages","source-family","routing","moderate","document-level","completeness","because","some","point","to","attachments","rather","than","exposing","the","full","attachment","text","in","this","environment","low","mnd","china","military","online","current-page","extraction","those","families","require","later","direct","access","dated","capture","independent","verification","of","claims","unless","corroborated","by","dod","odni","taiwan","allied","legal","audit","research","or","other","sources"]},{"title":"Red Sea Maritime Economics And Insurance Source Packet","type":"Source Packet","path":"library/collections/source-packets/red-sea-maritime-economics/2026-06-13T0258Z-red-sea-maritime-economics-insurance-source-packet.html","summary":"The Red Sea disruption file is a strategic-economic problem as much as a maritime-security problem. UNCTAD shows that pressure on the Red Sea, Suez Canal, Gulf of Aden, and related chokepoints lengthened shipping routes, raised ton-mile demand, increased fuel, crew, chartering, insurance, and emissions costs, and pushed freight rates upward. Suez Canal Authority annual reports provide the official canal-traffic baseline: recorded vessel transits fell from 26,434 in 2023 to 13,213 in 2024 and 12,758 in 2025, while net ton fell from 1,568.257 million tons in 2023 to 524.527 million tons in 2024 and 522.084 million tons in 2025. Allianz adds the marine-insurance perspective: political risk, conflict exposure, war cover, accumulation risk, and high-risk transit premiums are now central to shipping-sector risk analysis.","productId":"WI-SOURCEPACKET-REDSEA-ECON-2026-0001","preparedUtc":"2026-06-13T02:58:21Z","cutoffUtc":"2026-06-13T02:58:21Z","confidence":"High for official source identity, Suez Canal Authority traffic statistics, UN legal-diplomatic framing, EU mission framing, and UNCTAD headline maritime-disruption indicators. Moderate for marine insurance effects, commercial behavior, port-level second-order effects, and future persistence because insurance pricing, shipper behavior, and incident tempo change quickly and public data often lags.","theater":"Middle East / Maritime","domain":"Source Packets","tags":["red","sea","maritime","economics","and","insurance","source","packet","collections","source-packets","red-sea-maritime-economics","2026-06-13t0258z-red-sea-maritime-economics-insurance-source-packet","source packet","middle east / maritime","source packets","wi-sourcepacket-redsea-econ-2026-0001","2026-06-13t02:58:21z","high","for","official","identity","suez","canal","authority","traffic","statistics","un","legal-diplomatic","framing","eu","mission","unctad","headline","maritime-disruption","indicators","moderate","marine","effects","commercial","behavior","port-level","second-order","future","persistence","because","pricing","shipper","incident","tempo","change","quickly","public","data","often","lags"]},{"title":"Red Sea Maritime Economics Source Packets","type":"Directory","path":"library/collections/source-packets/red-sea-maritime-economics/index.html","summary":"Red Sea Maritime Economics Source Packets organize public evidence on Suez exposure, freight rates, ports, marine insurance, commercial risk, energy transit, and humanitarian logistics.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Middle East / Maritime","domain":"Red Sea Maritime Economics","tags":["red","sea","maritime","economics","source","packets","collections","source-packets","red-sea-maritime-economics","readme","directory","middle east / maritime","red sea maritime economics"]},{"title":"Republic Of Korea Official Defense And Extended Deterrence Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-allied-posture/2026-06-14T0158Z-republic-of-korea-official-defense-extended-deterrence-source-packet.html","summary":"The ROK source lane should be treated as a peninsula-front-line allied file with an extended-deterrence spine and a trilateral Indo-Pacific branch. The strongest verified public sources in this packet are ROK MOFA diplomatic sources, the Washington Declaration, Camp David source material, and the July 2024 trilateral defense ministerial statement. Together they support a high-confidence source lane for U.S.-ROK alliance assurance, DPRK nuclear and cyber threat framing, and U.S.-Japan-ROK institutionalization.","productId":"WI-SOURCEPACKET-ROK-ALLY-2026-0001","preparedUtc":"2026-06-14T01:58:34Z","cutoffUtc":"2026-06-14T01:58:34Z","confidence":"High for ROK MOFA diplomatic, DPRK nuclear, DPRK cyber-threat, Camp David, Washington Declaration, and trilateral ministerial source identity. Moderate for current ROK defense-ministry, acquisition, budget, readiness, and implementation evidence because the ROK MND and DAPA English front doors returned access-blocked test-site pages in this environment and require direct official document verification.","theater":"Collections","domain":"Source Packets","tags":["republic","of","korea","official","defense","and","extended","deterrence","source","packet","collections","source-packets","indo-pacific-allied-posture","2026-06-14t0158z-republic-of-korea-official-defense-extended-deterrence-source-packet","source packet","source packets","wi-sourcepacket-rok-ally-2026-0001","2026-06-14t01:58:34z","high","for","rok","mofa","diplomatic","dprk","nuclear","cyber-threat","camp","david","washington","declaration","trilateral","ministerial","identity","moderate","current","defense-ministry","acquisition","budget","readiness","implementation","evidence","because","the","mnd","dapa","english","front","doors","returned","access-blocked","test-site","pages","in","this","environment","require","direct","document","verification"]},{"title":"Russia Strategic Weapons And Nuclear Signaling Source Packet","type":"Source Packet","path":"library/collections/source-packets/strategic-weapons/2026-06-13T2051Z-russia-strategic-weapons-and-nuclear-signaling-source-packet.html","summary":"Russia is the most mature Russia-specific strategic-weapons lane in the current WARLOCK-INDEX corpus because it connects nuclear peer status, active war in Ukraine, NATO deterrence and assurance, nonstrategic nuclear concern, arms-control erosion, advanced delivery systems, counterspace risk, and homeland missile-warning pressure.","productId":"WI-SOURCEPACKET-RUSSIA-STRATWEAPONS-2026-0001","preparedUtc":"2026-06-13T20:51:37Z","cutoffUtc":"2026-06-13T20:51:37Z","confidence":"High for official public source identity, stated source language, treaty-source identity, and the durable relevance of Russian nuclear modernization, nuclear signaling, arms-control erosion, missile delivery systems, and counterspace concerns. Moderate for current force trajectory, nonstrategic nuclear-force detail, post-New START behavior, and future signaling patterns because public sources omit classified posture, readiness, decision thresholds, and intelligence sourcing.","theater":"Global","domain":"Source Packets","tags":["russia","strategic","weapons","and","nuclear","signaling","source","packet","collections","source-packets","strategic-weapons","2026-06-13t2051z-russia-strategic-weapons-and-nuclear-signaling-source-packet","source packet","global","source packets","wi-sourcepacket-russia-stratweapons-2026-0001","2026-06-13t20:51:37z","high","for","official","public","identity","stated","language","treaty-source","the","durable","relevance","of","russian","modernization","arms-control","erosion","missile","delivery","systems","counterspace","concerns","moderate","current","force","trajectory","nonstrategic","nuclear-force","detail","post-new","start","behavior","future","patterns","because","sources","omit","classified","posture","readiness","decision","thresholds","intelligence","sourcing"]},{"title":"Source Packets","type":"Directory","path":"library/collections/source-packets/index.html","summary":"Source Packets are reusable evidence packages that preserve official sources, source-class notes, extraction rules, cross-links, and information gaps.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Source Packets","tags":["source","packets","collections","source-packets","readme","directory","source packets"]},{"title":"South China Sea Coercion And Legal-Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T1946Z-south-china-sea-coercion-legal-source-packet.html","summary":"The South China Sea lane now needs three source layers kept separate at all times: coercion evidence, legal-source provenance, and map/issuer-language orientation. DoD 2025 provides the public U.S. defense assessment spine for China Coast Guard, China Maritime Militia, PLA Navy overwatch, lawfare, Philippines-focused pressure, contested outpost support, and coercive maritime tactics. PCA and State Limits in the Seas source families provide legal/procedural source routing, not WARLOCK-INDEX legal advice or navigation authority. Philippine official source families, including BFAR, provide issuer-perspective incident and maritime-rights material that must be dated and cross-read before analytic strengthening.","productId":"WI-SOURCEPACKET-CHINA-SCS-COERCION-2026-0001","preparedUtc":"2026-06-14T19:46:19Z","cutoffUtc":"2026-06-14T19:46:19Z","confidence":"High for DoD 2025 section identity, PCA case-page source-family identity, State Limits in the Seas source-family identity, BFAR October 15, 2024 press-release page identity, and the existing WARLOCK-INDEX map/legal source-routing spine. Moderate for Philippine Official Gazette, State Philippines, NAMRIA exact product-page, PRC MND, China Military Online, and China Coast Guard direct current-page extraction because several source families require manual refresh or translation checks before claim-level use. Lower for PRC operational intent, crisis thresholds, militia tasking, claimant state risk tolerance, and legal effect because public sources are partial, politically framed, contested, and often translated.","theater":"Collections","domain":"Source Packets","tags":["south","china","sea","coercion","and","legal-source","packet","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t1946z-south-china-sea-coercion-legal-source-packet","source packet","source packets","wi-sourcepacket-china-scs-coercion-2026-0001","2026-06-14t19:46:19z","high","for","dod","2025","section","identity","pca","case-page","source-family","state","limits","in","the","seas","bfar","october","15","2024","press-release","page","existing","warlock-index","map","legal","source-routing","spine","moderate","philippine","official","gazette","philippines","namria","exact","product-page","prc","mnd","military","online","coast","guard","direct","current-page","extraction","because","several","source","families","require","manual","refresh","or","translation","checks","before","claim-level","use","lower","operational","intent","crisis","thresholds","militia","tasking","claimant","risk","tolerance","effect","public","sources","are","partial","politically","framed","contested","often","translated"]},{"title":"Strategic Weapons Official Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/strategic-weapons/2026-06-13T0239Z-strategic-weapons-official-source-baseline-packet.html","summary":"The strategic-weapons evidence base needs disciplined layering. ODNI provides the current public Intelligence Community threat frame; the 2022 NDS/NPR/MDR provides the integrated U.S. defense, nuclear, and missile-defense policy baseline; the DoD PRC report provides actor-specific depth on China's nuclear, missile, space, and counterspace modernization; State Department New START materials provide the arms-control baseline; and WARLOCK-INDEX timelines and actor files connect those sources across theaters and domains. No single official source is sufficient by itself. The strongest strategic analysis comes from cross-reading threat assessments, policy documents, actor-specific military reports, treaty materials, allied declarations, and dated WARLOCK-INDEX products.","productId":"WI-SOURCEPACKET-STRATWEAPONS-2026-0001","preparedUtc":"2026-06-13T02:39:22Z","cutoffUtc":"2026-06-13T02:39:22Z","confidence":"High for official public source identity, publication date, stated scope, and durable source relevance. Moderate for derived judgments about source sufficiency because official public products differ in release cadence, policy context, classification limits, and methodology.","theater":"Global","domain":"Source Packets","tags":["strategic","weapons","official","source","baseline","packet","collections","source-packets","strategic-weapons","2026-06-13t0239z-strategic-weapons-official-source-baseline-packet","source packet","global","source packets","wi-sourcepacket-stratweapons-2026-0001","2026-06-13t02:39:22z","high","for","public","identity","publication","date","stated","scope","and","durable","relevance","moderate","derived","judgments","about","sufficiency","because","products","differ","in","release","cadence","policy","context","classification","limits","methodology"]},{"title":"Strategic Weapons Source Packets","type":"Directory","path":"library/collections/source-packets/strategic-weapons/index.html","summary":"Strategic Weapons Source Packets organize public evidence on modernization, deterrence, missile defense, arms control, counterspace, WMD concerns, and warning.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Global","domain":"Strategic Weapons","tags":["strategic","weapons","source","packets","collections","source-packets","strategic-weapons","readme","directory","global","strategic weapons"]},{"title":"Sweden Official Defense, Security, And NATO Integration Source Packet","type":"Source Packet","path":"library/collections/source-packets/arctic-infrastructure/2026-06-14T0502Z-sweden-official-defense-security-nato-integration-source-packet.html","summary":"Sweden's official source lane should be treated as both a new NATO ally integration file and a total-defence rebuilding file. Government Offices of Sweden pages frame the 2025-2030 defence resolution as a major reinforcement of both military and civil defence, with Sweden's national capability presented as part of NATO collective defence. Swedish Armed Forces pages preserve the institutional mission frame: defending Sweden, defending allies, reinforcing NATO, maintaining national defence as the primary task, and integrating into NATO deterrence, defence, civil preparedness, and host-nation-support work.","productId":"WI-SOURCEPACKET-SWE-ALLY-2026-0001","preparedUtc":"2026-06-14T05:02:58Z","cutoffUtc":"2026-06-14T05:02:58Z","confidence":"High for Swedish official source identity, Defence Resolution 2025-2030 framing, NATO membership and integration framing, Swedish Armed Forces NATO source routing, FLF Finland framework-nation source identity, total-defence/civil-defence source identity, Nordic cooperation, and Swedish Civil Defence and Resilience Agency source-family identity. Moderate for force growth, delivery, readiness, procurement, host-nation support, FLF implementation, cyber maturity, civil-defence implementation, and industrial output because those require follow-on budget, Riksdag, audit, procurement, agency, Armed Forces, NATO, and implementation-source refresh.","theater":"Arctic / High North","domain":"Source Packets","tags":["sweden","official","defense","security","and","nato","integration","source","packet","collections","source-packets","arctic-infrastructure","2026-06-14t0502z-sweden-official-defense-security-nato-integration-source-packet","source packet","arctic / high north","source packets","wi-sourcepacket-swe-ally-2026-0001","2026-06-14t05:02:58z","high","for","swedish","identity","defence","resolution","2025-2030","framing","membership","armed","forces","routing","flf","finland","framework-nation","total-defence","civil-defence","nordic","cooperation","civil","resilience","agency","source-family","moderate","force","growth","delivery","readiness","procurement","host-nation","support","implementation","cyber","maturity","industrial","output","because","those","require","follow-on","budget","riksdag","audit","implementation-source","refresh"]},{"title":"Taiwan Pressure And Cross-Strait Coercion Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-adversary-posture/2026-06-14T1938Z-taiwan-pressure-cross-strait-coercion-source-packet.html","summary":"Taiwan pressure is now a standing source lane rather than a single event file. DoD 2025 provides the current public U.S. defense assessment spine for PLA pressure, Taiwan Strait and South China Sea context, force-employment categories, and coercion-special-topic routing. ODNI 2026 provides the public intelligence caveat that Beijing probably still seeks conditions for unification short of conflict and does not have a fixed publicly assessed invasion timeline, while continuing to build coercive and military options. The Taiwan Relations Act provides U.S. statutory policy language around peace, stability, coercion, and defensive capacity.","productId":"WI-SOURCEPACKET-CHINA-TAIWAN-COERCION-2026-0001","preparedUtc":"2026-06-14T19:38:22Z","cutoffUtc":"2026-06-14T19:38:22Z","confidence":"High for DoD 2025 section identity, ODNI 2026 public assessment identity, Taiwan Relations Act statutory source identity, and State Council 2022 Taiwan white-paper release-page identity. Moderate for Taiwan MND, State, and AIT direct current-page extraction because those source families returned access errors or access caveats in this environment. Lower for PRC leadership intent, crisis thresholds, coercive sequencing, PLA readiness, Taiwan resilience, allied crisis behavior, and economic effects because public sources are partial, politically framed, dynamic, and often classified or contested.","theater":"Collections","domain":"Source Packets","tags":["taiwan","pressure","and","cross-strait","coercion","source","packet","collections","source-packets","indo-pacific-adversary-posture","2026-06-14t1938z-taiwan-pressure-cross-strait-coercion-source-packet","source packet","source packets","wi-sourcepacket-china-taiwan-coercion-2026-0001","2026-06-14t19:38:22z","high","for","dod","2025","section","identity","odni","2026","public","assessment","relations","act","statutory","state","council","2022","white-paper","release-page","moderate","mnd","ait","direct","current-page","extraction","because","those","families","returned","access","errors","or","caveats","in","this","environment","lower","prc","leadership","intent","crisis","thresholds","coercive","sequencing","pla","readiness","resilience","allied","behavior","economic","effects","sources","are","partial","politically","framed","dynamic","often","classified","contested"]},{"title":"Theater Map Reference Source Packets","type":"Directory","path":"library/collections/source-packets/theater-map-reference/index.html","summary":"Theater Map Reference Source Packets organize public map and geospatial sources with anchors, source-class notes, extraction rules, cross-links, and gaps.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Theater Map Reference","tags":["theater","map","reference","source","packets","collections","source-packets","theater-map-reference","readme","directory","theater map reference"]},{"title":"U.S.-Japan-ROK Trilateral Implementation Source Packet","type":"Source Packet","path":"library/collections/source-packets/indo-pacific-allied-posture/2026-06-14T0021Z-us-japan-rok-trilateral-implementation-source-packet.html","summary":"The public implementation record shows Camp David moving from leader-level principles into a standing but still source-limited architecture. The strongest official evidence is institutional rather than operational: annual leader and ministerial tracks, an annual Trilateral Indo-Pacific Dialogue, an inaugural January 2024 Indo-Pacific Dialogue, a July 2024 defense ministerial meeting in Japan, and a Trilateral Security Cooperation Framework for defense authorities.","productId":"WI-SOURCEPACKET-INDOPAC-ALLY-2026-0002","preparedUtc":"2026-06-14T00:21:47Z","cutoffUtc":"2026-06-14T00:21:47Z","confidence":"High for official source identity, the Camp David framework, the inaugural Trilateral Indo-Pacific Dialogue, the July 2024 defense ministerial meeting, and the announced Trilateral Security Cooperation Framework. Moderate for implementation depth, political durability, real-time technical performance, exercise learning, and crisis behavior because public sources omit classified readiness, sensor architecture, rules, contingency planning, and domestic political decision thresholds.","theater":"Collections","domain":"Source Packets","tags":["-japan-rok","trilateral","implementation","source","packet","collections","source-packets","indo-pacific-allied-posture","2026-06-14t0021z-us-japan-rok-trilateral-implementation-source-packet","source packet","source packets","wi-sourcepacket-indopac-ally-2026-0002","2026-06-14t00:21:47z","high","for","official","identity","the","camp","david","framework","inaugural","indo-pacific","dialogue","july","2024","defense","ministerial","meeting","and","announced","security","cooperation","moderate","depth","political","durability","real-time","technical","performance","exercise","learning","crisis","behavior","because","public","sources","omit","classified","readiness","sensor","architecture","rules","contingency","planning","domestic","decision","thresholds"]},{"title":"United Kingdom Official Defense And Security Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/nato-allied-capacity/2026-06-14T0118Z-uk-official-defense-security-source-baseline-packet.html","summary":"The United Kingdom official-source lane should be treated as a layered source stack. The Strategic Defence Review 2025 is the current top-level defense review and establishes the \"NATO first\" and warfighting-readiness public frame. The Integrated Review 2021 and Integrated Review Refresh 2023 provide the broader national security and foreign policy frame. The 2021 and 2023 defense command papers explain how Defence interpreted those national security reviews before the 2025 SDR. The nuclear, industrial, cyber, space, AI, resilience, terrorism, and biological security publications provide domain source lanes.","productId":"WI-SOURCEPACKET-UK-ALLY-2026-0001","preparedUtc":"2026-06-14T01:18:31Z","cutoffUtc":"2026-06-14T01:18:31Z","confidence":"High for official UK source identity, publication dates, departmental ownership, and declared policy framing. Moderate for implementation judgments because official strategy papers do not by themselves verify readiness, delivery schedules, stockpile depth, workforce capacity, industrial output, classified threat assessment, or budget execution.","theater":"Collections","domain":"Source Packets","tags":["united","kingdom","official","defense","and","security","source","baseline","packet","collections","source-packets","nato-allied-capacity","2026-06-14t0118z-uk-official-defense-security-source-baseline-packet","source packet","source packets","wi-sourcepacket-uk-ally-2026-0001","2026-06-14t01:18:31z","high","for","uk","identity","publication","dates","departmental","ownership","declared","policy","framing","moderate","implementation","judgments","because","strategy","papers","do","not","by","themselves","verify","readiness","delivery","schedules","stockpile","depth","workforce","capacity","industrial","output","classified","threat","assessment","or","budget","execution"]},{"title":"WMD/Biosecurity Public Source Baseline Packet","type":"Source Packet","path":"library/collections/source-packets/official-threat-source-baseline/2026-06-14T0358Z-wmd-biosecurity-public-source-baseline-packet.html","summary":"WARLOCK-INDEX should treat WMD/biosecurity as a source-discipline problem before it treats it as an analytic-judgment problem. The public source lane is fragmented across intelligence disclosure, biodefense strategy, defense threat reduction, law-enforcement prevention, select-agent oversight, arms-control/treaty governance, congressional biotechnology-security review, and allied or multilateral biological-security sources.","productId":"WI-SOURCEPACKET-US-WMDBIO-2026-0001","preparedUtc":"2026-06-14T03:58:59Z","cutoffUtc":"2026-06-14T03:58:59Z","confidence":"High for source identity and broad source-family routing. Moderate for source completeness because State and UNODA treaty pages returned access barriers in this environment and because several biosecurity source families require document-level refresh before carrying specific legal, technical, or oversight claims.","theater":"Collections","domain":"Source Packets","tags":["wmd","biosecurity","public","source","baseline","packet","collections","source-packets","official-threat-source-baseline","2026-06-14t0358z-wmd-biosecurity-public-source-baseline-packet","source packet","source packets","wi-sourcepacket-us-wmdbio-2026-0001","2026-06-14t03:58:59z","high","for","identity","and","broad","source-family","routing","moderate","completeness","because","state","unoda","treaty","pages","returned","access","barriers","in","this","environment","several","families","require","document-level","refresh","before","carrying","specific","legal","technical","or","oversight","claims"]},{"title":"Foreign Government Reference Source Register","type":"Source Register","path":"library/source-registers/foreign-government-reference.html","summary":"Define source-routing rules for foreign government leadership, officeholder, diplomatic, country, and official-government reference material used inside WARLOCK-INDEX.","productId":"WI-SOURCE-REGISTER-FGOV-2026-0001","preparedUtc":"2026-06-14T19:46:19Z","cutoffUtc":"2026-06-14T19:46:19Z","confidence":"","theater":"Global","domain":"Sources","tags":["foreign","government","reference","source","register","source-registers","foreign-government-reference","source register","global","sources","wi-source-register-fgov-2026-0001","2026-06-14t19:46:19z"]},{"title":"Map And Geospatial Reference Source Register","type":"Source Register","path":"library/source-registers/map-geospatial-reference.html","summary":"Define source-routing rules for public map, geographic-name, topographic, nautical, command-area, and geospatial reference material used inside WARLOCK-INDEX.","productId":"WI-SOURCE-REGISTER-MAPGEO-2026-0001","preparedUtc":"2026-06-14T19:46:19Z","cutoffUtc":"2026-06-14T19:46:19Z","confidence":"","theater":"Global","domain":"Sources","tags":["map","and","geospatial","reference","source","register","source-registers","map-geospatial-reference","source register","global","sources","wi-source-register-mapgeo-2026-0001","2026-06-14t19:46:19z"]},{"title":"Maritime Chokepoints Source Register","type":"Source Register","path":"library/source-registers/maritime-chokepoints.html","summary":"Organize source families for maritime chokepoint analysis across Red Sea/Suez, Hormuz, Malacca/Singapore, Panama, Black Sea, and Arctic lanes.","productId":"WI-SOURCE-REGISTER-MARITIME-2026-0001","preparedUtc":"2026-06-14T19:46:19Z","cutoffUtc":"2026-06-14T19:46:19Z","confidence":"","theater":"Global","domain":"Sources","tags":["maritime","chokepoints","source","register","source-registers","maritime-chokepoints","source register","global","sources","wi-source-register-maritime-2026-0001","2026-06-14t19:46:19z"]},{"title":"Official U.S. Intelligence And Law Enforcement Source Register","type":"Source Register","path":"library/source-registers/us-intelligence-law-enforcement.html","summary":"Organize official U.S. intelligence, homeland security, law enforcement, sanctions, border, cyber, counterterrorism, counternarcotics, and geospatial source families for WARLOCK-INDEX strategic threat analysis.","productId":"WI-SOURCE-REGISTER-USILE-2026-0001","preparedUtc":"2026-06-14T19:56:06Z","cutoffUtc":"2026-06-14T19:56:06Z","confidence":"","theater":"Global","domain":"Sources","tags":["official","intelligence","and","law","enforcement","source","register","source-registers","us-intelligence-law-enforcement","source register","global","sources","wi-source-register-usile-2026-0001","2026-06-14t19:56:06z"]},{"title":"Assessment Style Guide","type":"Standard","path":"library/standards/assessment-style-guide.html","summary":"Write in clear, disciplined prose. The tone should be sober, direct, and human: more like a serious defense assessment than a generic report.","productId":"WI-STD-003","preparedUtc":"2026-06-12T23:20:35Z","cutoffUtc":"","confidence":"","theater":"Global","domain":"Tradecraft","tags":["assessment","style","guide","standards","assessment-style-guide","standard","global","tradecraft","wi-std-003","2026-06-12t23:20:35z"]},{"title":"Datetime And Versioning Standard","type":"Standard","path":"library/standards/datetime-and-versioning.html","summary":"Use ISO 8601 UTC timestamps:","productId":"WI-STD-004","preparedUtc":"2026-06-12T23:20:35Z","cutoffUtc":"","confidence":"","theater":"Global","domain":"Tradecraft","tags":["datetime","and","versioning","standard","standards","datetime-and-versioning","global","tradecraft","wi-std-004","2026-06-12t23:20:35z"]},{"title":"Assessment Template","type":"Template","path":"library/templates/assessment-template.html","summary":"One concise paragraph stating the main assessment.","productId":"WI-ASMT-AREA-YEAR-NNNN","preparedUtc":"YYYY-MM-DDTHH:MM:SSZ","cutoffUtc":"YYYY-MM-DDTHH:MM:SSZ","confidence":"High / Moderate / Low","theater":"Templates","domain":"Templates","tags":["assessment","template","templates","assessment-template","wi-asmt-area-year-nnnn","yyyy-mm-ddthh:mm:ssz","high","moderate","low"]},{"title":"Allied Official Source Collection Tracker","type":"Tracker","path":"library/collections/trackers/2026-06-14T0118Z-allied-official-source-collection-tracker.html","summary":"The allied-source lane should expand through national, multilateral, and clearly labeled strategic-partner official-source stacks. The United Kingdom, Australia, Canada/NORAD, Japan, the Republic of Korea, France, Germany, Norway, Finland, and Sweden are now the first country or continental-defense lanes to receive U.S.-style official source baselines. Denmark, Iceland, and the EU now extend that architecture across the remaining Nordic/North Atlantic country-source lanes and the EU-level security-defense layer. India/Quad now adds the first partner-lane source packet and preserves the distinction between treaty-allied evidence and Quad strategic-partner evidence. NATO provides the shared Alliance frame, while country lanes should capture national strategy, defense review, budget/procurement evidence, industrial policy, nuclear or extended-deterrence sources where applicable, cyber agencies, space agencies, resilience systems, and parliamentary/audit evidence.","productId":"WI-TRACKER-ALLY-SOURCES-2026-0001","preparedUtc":"2026-06-16T05:12:39Z","cutoffUtc":"2026-06-16T05:12:39Z","confidence":"High for collection architecture and already registered UK, Australia, AUKUS, Canada/NORAD, NORAD modernization, Japan, ROK, France, Germany, Norway, Finland, Sweden, Denmark, Iceland, EU, and NATO source families, plus India/Quad partner-source identity and source-family routing. Moderate for the wider ally queue because each remaining national lane still needs its own dated verification and source packet.","theater":"Collections","domain":"Trackers","tags":["allied","official","source","collection","tracker","collections","trackers","2026-06-14t0118z-allied-official-source-collection-tracker","wi-tracker-ally-sources-2026-0001","2026-06-16t05:12:39z","high","for","architecture","and","already","registered","uk","australia","aukus","canada","norad","modernization","japan","rok","france","germany","norway","finland","sweden","denmark","iceland","eu","nato","families","plus","india","quad","partner-source","identity","source-family","routing","moderate","the","wider","ally","queue","because","each","remaining","national","lane","still","needs","its","own","dated","verification","packet"]},{"title":"Arms-Control Erosion Strategic Tracker","type":"Tracker","path":"library/collections/trackers/2026-06-13T0319Z-arms-control-erosion-strategic-tracker.html","summary":"Arms-control erosion is a strategic-stability tracker because it changes the information environment around nuclear and strategic weapons competition. New START's expiration on February 5, 2026, after Russian suspension in 2023, marks the loss of the last legally binding bilateral U.S.-Russia strategic nuclear arms limit. That loss does not automatically prove immediate force expansion, but it does reduce treaty-based verification, data exchange, inspection rights, and predictability.","productId":"WI-TRACKER-ARMSCONTROL-2026-0001","preparedUtc":"2026-06-13T03:19:18Z","cutoffUtc":"2026-06-13T03:16:36Z","confidence":"High for broad treaty-status categories where official or well-established research sources converge. Moderate for current implementation behavior, informal restraint, post-expiration transparency, and future negotiating prospects.","theater":"Collections","domain":"Trackers","tags":["arms-control","erosion","strategic","tracker","collections","trackers","2026-06-13t0319z-arms-control-erosion-strategic-tracker","wi-tracker-armscontrol-2026-0001","2026-06-13t03:19:18z","2026-06-13t03:16:36z","high","for","broad","treaty-status","categories","where","official","or","well-established","research","sources","converge","moderate","current","implementation","behavior","informal","restraint","post-expiration","transparency","and","future","negotiating","prospects"]},{"title":"China/PLA Source Collection Tracker","type":"Tracker","path":"library/collections/trackers/2026-06-14T0523Z-china-pla-source-collection-tracker.html","summary":"Track China and PLA source-family collection across official U.S., PRC issuer, Taiwan, allied/regional, cyber, legal, map, industrial, technology, and WARLOCK-INDEX derived products.","productId":"WI-TRACKER-CHINA-PLA-SOURCES-2026-0001","preparedUtc":"2026-06-14T19:56:06Z","cutoffUtc":"2026-06-14T19:56:06Z","confidence":"","theater":"Collections","domain":"Trackers","tags":["china","pla","source","collection","tracker","collections","trackers","2026-06-14t0523z-china-pla-source-collection-tracker","wi-tracker-china-pla-sources-2026-0001","2026-06-14t19:56:06z"]},{"title":"Official Threat Source Collection Tracker","type":"Tracker","path":"library/collections/trackers/2026-06-13T0600Z-official-threat-source-collection-tracker.html","summary":"The official-source lane should expand through dated source packets, not a single sprawling enemies document. This tracker identifies which agency source families are already usable, which need dedicated packets, and which safety boundaries must be preserved before the corpus makes stronger judgments.","productId":"WI-TRACKER-US-THREAT-SOURCES-2026-0001","preparedUtc":"2026-06-14T06:05:33Z","cutoffUtc":"2026-06-14T06:05:33Z","confidence":"High for collection architecture. Moderate for source recency because dynamic agency pages and annual reports require dated refreshes.","theater":"Collections","domain":"Trackers","tags":["official","threat","source","collection","tracker","collections","trackers","2026-06-13t0600z-official-threat-source-collection-tracker","wi-tracker-us-threat-sources-2026-0001","2026-06-14t06:05:33z","high","for","architecture","moderate","recency","because","dynamic","agency","pages","and","annual","reports","require","dated","refreshes"]},{"title":"Red Sea Maritime Disruption Strategic Tracker","type":"Tracker","path":"library/collections/trackers/2026-06-13T0518Z-red-sea-maritime-disruption-strategic-tracker.html","summary":"Red Sea disruption should be tracked as an aggregate strategic system rather than as a list of incidents alone. The key families are Houthi posture, Iran-linked support context, commercial shipping behavior, Suez Canal traffic, marine insurance, allied and multilateral response, humanitarian and port effects, and legal-designation changes. Each indicator moves at a different speed, so WARLOCK-INDEX should avoid false precision and keep all outputs at strategic level.","productId":"WI-TRACKER-REDSEA-2026-0001","preparedUtc":"2026-06-13T05:18:00Z","cutoffUtc":"2026-06-13T05:18:00Z","confidence":"High for official source identity, source class, UN and EU framing, and Suez Canal Authority traffic statistics. Moderate for commercial market persistence, insurance pricing, Houthi decision calculus, and future incident tempo.","theater":"Collections","domain":"Trackers","tags":["red","sea","maritime","disruption","strategic","tracker","collections","trackers","2026-06-13t0518z-red-sea-maritime-disruption-strategic-tracker","wi-tracker-redsea-2026-0001","2026-06-13t05:18:00z","high","for","official","source","identity","class","un","and","eu","framing","suez","canal","authority","traffic","statistics","moderate","commercial","market","persistence","insurance","pricing","houthi","decision","calculus","future","incident","tempo"]},{"title":"Trackers","type":"Directory","path":"library/collections/trackers/index.html","summary":"Trackers are structured collection products that connect actors, events, domains, sources, and strategic effects. They are not policy recommendations and do not provide operational guidance.","productId":"","preparedUtc":"","cutoffUtc":"","confidence":"","theater":"Collections","domain":"Trackers","tags":["trackers","collections","readme","directory"]},{"title":"Ukraine War External Support Tracker","type":"Tracker","path":"library/collections/trackers/2026-06-13T0120Z-ukraine-war-external-support-tracker.html","summary":"Russia's war against Ukraine is now a global external-support system, not only a bilateral war. NATO and ODNI public sources identify support to Ukraine from Allies and partners, and support to Russia or enabling activity from China, Iran, North Korea, and Belarus. The external-support problem affects defense industrial capacity, sanctions resilience, air and missile defense demand, munitions production, drone adaptation, logistics, training, battlefield learning, alliance cohesion, and selective adversary alignment.","productId":"WI-TRACKER-UKRAINE-2026-0001","preparedUtc":"2026-06-13T01:20:58Z","cutoffUtc":"2026-06-13T01:20:58Z","confidence":"High for broad categories identified in official NATO and ODNI public sources; moderate for quantities, timelines, technical details, commercial intermediaries, sanctions-evasion pathways, and reciprocal benefits among Russia, China, Iran, and North Korea.","theater":"Collections","domain":"Trackers","tags":["ukraine","war","external","support","tracker","collections","trackers","2026-06-13t0120z-ukraine-war-external-support-tracker","wi-tracker-ukraine-2026-0001","2026-06-13t01:20:58z","high","for","broad","categories","identified","in","official","nato","and","odni","public","sources","moderate","quantities","timelines","technical","details","commercial","intermediaries","sanctions-evasion","pathways","reciprocal","benefits","among","russia","china","iran","north","korea"]}];
